PIN_ROLE_INPUT = "input"
PIN_ROLE_OUTPUT = "output"
PIN_ROLE_HIDDEN = "hidden"
PIN_ROLE_ORDER = [PIN_ROLE_INPUT, PIN_ROLE_HIDDEN, PIN_ROLE_OUTPUT]
PIN_SLOT_SAFE_DEFAULT_VALUE = 1.0
PIN_SLOT_MAX_MAGNITUDE = 1024.0
LATENT_LOGVAR_MIN = -20.0
LATENT_LOGVAR_MAX = 20.0
LOG_ALPHA_MIN = -20.0
LOG_ALPHA_MAX = 20.0
LATENT_SAMPLE_CLAMP = 1_000.0
LOSS_VALUE_CLAMP = 1_000_000.0


def _normalize_pin_role(value: Any) -> str | None:
    if isinstance(value, str):
        role = value.strip().lower()
        if role in {PIN_ROLE_INPUT, PIN_ROLE_HIDDEN, PIN_ROLE_OUTPUT}:
            return role
    return None


def _sanitize_pin_slot_scalar(value: torch.Tensor) -> torch.Tensor:
    """Clamp NaN/Inf pin-slot logits to a bounded, finite range."""
    safe = torch.nan_to_num(
        value,
        nan=PIN_SLOT_SAFE_DEFAULT_VALUE,
        posinf=PIN_SLOT_MAX_MAGNITUDE,
        neginf=-PIN_SLOT_MAX_MAGNITUDE,
    )
    return safe.clamp(min=-PIN_SLOT_MAX_MAGNITUDE, max=PIN_SLOT_MAX_MAGNITUDE)


def _sanitize_logvar(value: torch.Tensor) -> torch.Tensor:
    safe = torch.nan_to_num(value, nan=0.0, posinf=LATENT_LOGVAR_MAX, neginf=LATENT_LOGVAR_MIN)
    return safe.clamp(min=LATENT_LOGVAR_MIN, max=LATENT_LOGVAR_MAX)


def _sanitize_log_alpha(value: torch.Tensor) -> torch.Tensor:
    safe = torch.nan_to_num(value, nan=0.0, posinf=LOG_ALPHA_MAX, neginf=LOG_ALPHA_MIN)
    return safe.clamp(min=LOG_ALPHA_MIN, max=LOG_ALPHA_MAX)


def _sanitize_latent_sample(value: torch.Tensor) -> torch.Tensor:
    safe = torch.nan_to_num(value, nan=0.0, posinf=LATENT_SAMPLE_CLAMP, neginf=-LATENT_SAMPLE_CLAMP)
    return safe.clamp(min=-LATENT_SAMPLE_CLAMP, max=LATENT_SAMPLE_CLAMP)


def _finite_loss(value: torch.Tensor, clamp: float = LOSS_VALUE_CLAMP) -> torch.Tensor:
    return torch.nan_to_num(value, nan=0.0, posinf=clamp, neginf=-clamp)


def flatten_task_features(task_features, expected_len: Optional[int] = None) -> np.ndarray:
    """Flatten heterogeneous task feature collections into a single 1D array with optional padding."""
    if isinstance(task_features, torch.Tensor):
        return task_features.detach().cpu().view(-1).numpy()
    if isinstance(task_features, np.ndarray):
        return task_features.reshape(-1)
    flat_parts: List[np.ndarray] = []
    for feat in task_features:
        if isinstance(feat, np.ndarray):
            flat_parts.append(feat.reshape(-1))
        elif isinstance(feat, torch.Tensor):
            flat_parts.append(feat.detach().cpu().view(-1).numpy())
        else:
            flat_parts.append(np.atleast_1d(np.asarray(feat)))
    if not flat_parts:
        flat = np.array([], dtype=float)
    else:
        flat = np.concatenate(flat_parts, axis=0)
    if expected_len is not None:
        if flat.size < expected_len:
            flat = np.pad(flat, (0, expected_len - flat.size))
        elif flat.size > expected_len:
            flat = flat[:expected_len]
    return flat


def _weisfeiler_lehman_histograms(
    node_types: torch.Tensor,
    edge_index: torch.Tensor,
    batch: torch.Tensor,
    num_graphs: int,
    *,
    node_attributes: Optional[Sequence[Any]] = None,
    iterations: int = 2,
) -> Optional[torch.Tensor]:
    """Compute WL subtree histogram per graph, mixing node types and attributes."""

    if num_graphs <= 1 or node_types.numel() == 0:
        return None

    node_types_cpu = node_types.detach().cpu().view(-1)
    edge_index_cpu = edge_index.detach().cpu()
    batch_cpu = batch.detach().cpu().view(-1)
    num_nodes = node_types_cpu.numel()
    attr_sequence: List[Any] = []
    if node_attributes is None:
        attr_sequence = []
    elif isinstance(node_attributes, (list, tuple)):
        attr_sequence = list(node_attributes)
    elif torch.is_tensor(node_attributes):
        attr_sequence = node_attributes.detach().cpu().view(-1).tolist()
    else:
        try:
            attr_sequence = list(node_attributes)
        except TypeError:
            attr_sequence = []
    adjacency: List[List[int]] = [[] for _ in range(num_nodes)]
    for src, dst in edge_index_cpu.t().tolist():
        adjacency[src].append(dst)

    attr_tokens: List[str] = []
    for idx in range(num_nodes):
        if idx < len(attr_sequence):
            attr_tokens.append(_wl_attribute_fingerprint(attr_sequence[idx]))
        else:
            attr_tokens.append("")
    colors: List[str] = []
    for idx, label in enumerate(node_types_cpu.tolist()):
        base = f"t{int(label)}"
        attr_sig = attr_tokens[idx]
        if attr_sig:
            attr_hash = hashlib.sha256(attr_sig.encode("utf-8")).hexdigest()[:16]
            base = f"{base}|a{attr_hash}"
        colors.append(base)
    for _ in range(max(1, iterations)):
        new_colors = []
        for idx in range(num_nodes):
            neighbors = adjacency[idx]
            if neighbors:
                neigh_colors = sorted(colors[n] for n in neighbors)
                combo = colors[idx] + "|" + "|".join(neigh_colors)
            else:
                combo = colors[idx] + "|"
            hashed = hashlib.sha256(combo.encode("utf-8")).hexdigest()[:16]
            new_colors.append(hashed)
        colors = new_colors

    vocab: Dict[str, int] = {}
    hist = torch.zeros((num_graphs, 0), dtype=torch.float32)
    counters: List[Counter] = [Counter() for _ in range(num_graphs)]
    for node_idx, color in enumerate(colors):
        graph_idx = int(batch_cpu[node_idx])
        counters[graph_idx][color] += 1
        if color not in vocab:
            vocab[color] = len(vocab)

    if not vocab:
        return None

    hist = torch.zeros((num_graphs, len(vocab)), dtype=torch.float32)
    for graph_idx, counter in enumerate(counters):
        for color, count in counter.items():
            col_idx = vocab[color]
            hist[graph_idx, col_idx] = float(count)
    row_sums = hist.sum(dim=1, keepdim=True).clamp_min(1e-6)
    hist = hist / row_sums
    return hist


class DAGAttention(MessagePassing):
    """
    DAG-specific attention aggregator (Chen et al. 2021).
    Each node attends over its predecessors + itself (node context).
    """

    def __init__(self, in_channels, out_channels, negative_slope=0.2):
        super().__init__(aggr="add")
        self.lin = nn.Linear(in_channels, out_channels, bias=False)
        self.att = nn.Parameter(torch.Tensor(1, 2 * out_channels))
        self.leaky_relu = nn.LeakyReLU(negative_slope)
        nn.init.kaiming_uniform_(self.lin.weight, negative_slope, mode="fan_in", nonlinearity="leaky_relu")
        nn.init.kaiming_uniform_(self.att, negative_slope, mode="fan_in", nonlinearity="leaky_relu")

    def forward(self, x, edge_index):
        x = self.lin(x)
        edge_index, _ = add_self_loops(edge_index, num_nodes=x.size(0))
        return self.propagate(edge_index, x=x)

    def message(self, x_i, x_j, index, ptr, size_i):
        cat = torch.cat([x_i, x_j], dim=-1)
        alpha = (cat * self.att).sum(dim=-1)
        alpha = self.leaky_relu(alpha)
        alpha = softmax(alpha, index, ptr, size_i)
        return x_j * alpha.view(-1, 1)

    def update(self, aggr_out):
        return F.relu(aggr_out)


class AsyncDAGLayer(nn.Module):
    """Simple asynchronous message passing layer following a topological order."""

    def __init__(self, in_channels, out_channels):
        super().__init__()
        self.lin = nn.Linear(in_channels, out_channels)

    def forward(self, x, edge_index):
        x = self.lin(x)
        num_nodes = x.size(0)
        device = x.device
        indeg = torch.zeros(num_nodes, dtype=torch.long, device=device)
        indeg.scatter_add_(0, edge_index[1], torch.ones(edge_index.size(1), dtype=torch.long, device=device))
        preds = [[] for _ in range(num_nodes)]
        for s, d in edge_index.t().tolist():
            preds[d].append(s)
        order = [n for n in range(num_nodes) if indeg[n] == 0]
        i = 0
        while i < len(order):
            n = order[i]
            mask = edge_index[0] == n
            for dest in edge_index[1][mask].tolist():
                indeg[dest] -= 1
                if indeg[dest] == 0:
                    order.append(dest)
            i += 1
        h = torch.zeros_like(x)
        for n in order:
            if preds[n]:
                agg = h[preds[n]].mean(dim=0)
                h[n] = F.relu(x[n] + agg)
            else:
                h[n] = F.relu(x[n])
        return h


class TasksEncoder(nn.Module):
    def __init__(self, hidden_dim: int, latent_dim: int, type_embedding_dim: int):
        super().__init__()
        # Separate module per task type because each task has different number of features
        # and features don't semantically align
        self.latent_dim = latent_dim
        self.embedder = nn.Embedding(len(TASK_FEATURE_DIMS), type_embedding_dim)
        self.encoders = nn.ModuleDict(
            {
                str(TASK_TYPE_TO_INDEX[type]): nn.Sequential(
                    nn.Linear(num_features + type_embedding_dim, hidden_dim),
                    nn.ReLU(),
                    nn.Linear(hidden_dim, hidden_dim),
                    nn.ReLU(),
                )
                for type, num_features in TASK_FEATURE_DIMS.items()
            }
        )
        # Shared mu/logvar heads
        self.lin_mu = nn.Linear(hidden_dim, latent_dim)
        self.lin_logvar = nn.Linear(hidden_dim, latent_dim)

    def forward(self, task_types, feature_vecs):
        mu_list, logvar_list = [], []
        for task_type, feature_vec in zip(task_types, feature_vecs):
            task_type_embedding = self.embedder(task_type)
            feature_vec = torch.as_tensor(feature_vec, dtype=torch.float).flatten()
            h = self.encoders[str(task_type.item())](torch.cat((task_type_embedding, feature_vec), dim=0))
            mu_list.append(self.lin_mu(h))
            logvar_list.append(self.lin_logvar(h))
        return torch.stack(mu_list, dim=0), torch.stack(logvar_list, dim=0)

    def reparameterize(self, mu, logvar):
        std = torch.exp(0.5 * logvar)
        z = mu + torch.randn_like(std) * std
        return z if self.latent_mask is None else z * self.latent_mask

    def prune_latent_dims(self, kept_idx: torch.LongTensor):
        def prune_lin(old):
            layer = nn.Linear(old.in_features, kept_idx.numel()).to(old.weight.device)
            layer.weight.data = old.weight.data[kept_idx]
            layer.bias.data = old.bias.data[kept_idx]
            return layer

        self.lin_mu = prune_lin(self.lin_mu)
        self.lin_logvar = prune_lin(self.lin_logvar)
        self.latent_dim = len(kept_idx)


class SharedAttributeVocab(nn.Module):
    """
    Holds one name-to-index mapping plus a single Embedding that
    can grow on‐the‐fly as new names are added.
    """

    VALUE_LITERAL_PREFIX = "__value__"

    def __init__(self, initial_names: List[str], embedding_dim: int):
        super().__init__()
        self.name_to_index = {name: i for i, name in enumerate(initial_names)}
        self.index_to_name = {i: name for name, i in self.name_to_index.items()}
        for token in ("<UNK>", "<EOS>", "<SOS>"):
            if token not in self.name_to_index:
                idx = len(self.name_to_index)
                self.name_to_index[token] = idx
                self.index_to_name[idx] = token
        self.embedding = nn.Embedding(len(self.name_to_index), embedding_dim)
        self._allowed_names: MutableSet[str] | None = None
        self._always_allowed = {"<UNK>", "<EOS>", "<SOS>"}
        self._banned_names = {"node_type"}

    @property
    def unk_index(self) -> int:
        return self.name_to_index["<UNK>"]

    @property
    def eos_index(self) -> int:
        return self.name_to_index["<EOS>"]

    @property
    def sos_index(self) -> int:
        return self.name_to_index["<SOS>"]

    def set_allowed_names(self, allowed_names: MutableSet[str] | Sequence[str] | None):
        if allowed_names is None:
            self._allowed_names = None
            return
        if isinstance(allowed_names, MutableSet):
            self._allowed_names = allowed_names
        else:
            self._allowed_names = set(allowed_names)

    def is_name_allowed(self, name: str) -> bool:
        if not name:
            return False
        if name in self._always_allowed:
            return True
        if name in self._banned_names:
            return False
        if name.startswith("__"):
            return True
        if self._allowed_names is None:
            return True
        return name in self._allowed_names

    def value_literal_token(self, literal: str) -> str:
        literal = "" if literal is None else str(literal)
        if literal.startswith(self.VALUE_LITERAL_PREFIX):
            return literal
        return f"{self.VALUE_LITERAL_PREFIX}{literal}"

    def ensure_value_literal(self, literal: str) -> int:
        return self.ensure_index(self.value_literal_token(literal))

    def add_names(self, new_names: List[str]):
        names_to_add: List[str] = []
        for name in new_names:
            if not isinstance(name, str):
                name = str(name)
            if name in self.name_to_index:
                continue
            if not self.is_name_allowed(name):
                if name in self._banned_names:
                    continue
                raise ValueError(f"Attribute name {name!r} not in allowed set")
            names_to_add.append(name)

        if not names_to_add:
            return

        starting_index = len(self.name_to_index)

        for offset, name in enumerate(names_to_add):
            new_idx = starting_index + offset
            self.name_to_index[name] = new_idx
            self.index_to_name[new_idx] = name

        # expand the embedding matrix with He‐style initialization for the new rows
        old_weight = self.embedding.weight.data
        fan_in = old_weight.size(1)
        device = old_weight.device
        new_rows = torch.randn(len(names_to_add), fan_in, device=device) * math.sqrt(2 / fan_in)
        new_weight = torch.cat([old_weight, new_rows], dim=0)
        self.embedding = nn.Embedding.from_pretrained(new_weight, freeze=False)

    def ensure_index(self, name: str) -> int:
        if name not in self.name_to_index:
            if name in self._banned_names:
                return self.unk_index
            if not self.is_name_allowed(name):
                raise ValueError(f"Attribute name {name!r} not in allowed set")
            self.add_names([name])
        idx = self.name_to_index[name]
        if idx >= self.embedding.num_embeddings:
            # expand just enough rows to accommodate idx
            missing = idx - self.embedding.num_embeddings + 1
            old_weight = self.embedding.weight.data
            fan_in = old_weight.size(1)
            device = old_weight.device
            new_rows = torch.randn(missing, fan_in, device=device) * math.sqrt(2 / fan_in)
            new_weight = torch.cat([old_weight, new_rows], dim=0)
            self.embedding = nn.Embedding.from_pretrained(new_weight, freeze=False)
        return idx


def attribute_key_to_name(attr_key: Any) -> str:
    if hasattr(attr_key, "name"):
        return attr_key.name  # neat attribute objects
    if isinstance(attr_key, str):
        return attr_key
    return str(attr_key)


def _serialize_attr_value_for_signature(value: Any) -> Any:
    if torch.is_tensor(value):
        if value.numel() == 0:
            return []
        return value.detach().cpu().view(-1).tolist()
    if isinstance(value, np.ndarray):
        if value.size == 0:
            return []
        return value.reshape(-1).tolist()
    if isinstance(value, (list, tuple)):
        return [_serialize_attr_value_for_signature(v) for v in value]
    if isinstance(value, dict):
        return {
            str(k): _serialize_attr_value_for_signature(v)
            for k, v in sorted(value.items(), key=lambda item: str(item[0]))
        }
    if isinstance(value, (bool, int, float, str)) or value is None:
        return value
    return repr(value)


def _serialize_node_types_for_signature(node_types) -> List[int]:
    if node_types is None:
        return []
    if torch.is_tensor(node_types):
        return node_types.detach().cpu().view(-1).tolist()
    if isinstance(node_types, np.ndarray):
        return node_types.reshape(-1).tolist()
    return list(node_types)


def _serialize_edge_index_for_signature(edge_index) -> List[List[int]]:
    if edge_index is None:
        return []
    if torch.is_tensor(edge_index):
        tensor = edge_index.detach().cpu().long()
        if tensor.dim() == 1:
            tensor = tensor.view(2, -1)
        if tensor.numel() == 0:
            return []
        return tensor.t().tolist()
    if isinstance(edge_index, np.ndarray):
        if edge_index.size == 0:
            return []
        arr = edge_index
        if arr.ndim == 1:
            arr = arr.reshape(2, -1)
        return arr.T.tolist()
    edges: List[List[int]] = []
    for edge in edge_index:
        if isinstance(edge, (list, tuple)):
            if len(edge) >= 2:
                edges.append([int(edge[0]), int(edge[1])])
        elif isinstance(edge, dict):
            src = int(edge.get("src", 0))
            dst = int(edge.get("dst", 0))
            edges.append([src, dst])
    return edges


def _serialize_node_attributes_for_signature(node_attributes) -> List[Any]:
    if not node_attributes:
        return []
    serialized_nodes: List[Any] = []
    for attrs in node_attributes:
        if not isinstance(attrs, dict):
            serialized_nodes.append(_serialize_attr_value_for_signature(attrs))
            continue
        serialized_attrs = []
        for key, value in sorted(attrs.items(), key=lambda item: attribute_key_to_name(item[0])):
            serialized_attrs.append([attribute_key_to_name(key), _serialize_attr_value_for_signature(value)])
        serialized_nodes.append(serialized_attrs)
    return serialized_nodes


def graph_signature_from_components(node_types, edge_index, node_attributes) -> str:
    payload = {
        "node_types": _serialize_node_types_for_signature(node_types),
        "edge_index": _serialize_edge_index_for_signature(edge_index),
        "node_attributes": _serialize_node_attributes_for_signature(node_attributes),
    }
    serialized = json.dumps(payload, sort_keys=True, separators=(",", ":"), ensure_ascii=True)
    return hashlib.sha256(serialized.encode("utf-8")).hexdigest()


def graph_signature_from_data(graph: Data) -> str:
    return graph_signature_from_components(
        getattr(graph, "node_types", None),
        getattr(graph, "edge_index", None),
        getattr(graph, "node_attributes", None),
    )


def graph_signature_from_dict(graph_dict: Dict[str, Any]) -> str:
    if not graph_dict:
        return hashlib.sha256(b"{}").hexdigest()
    return graph_signature_from_components(
        graph_dict.get("node_types"),
        graph_dict.get("edge_index"),
        graph_dict.get("node_attributes"),
    )


def group_node_attributes(node_attrs: Sequence[Any], batch_vec: Optional[torch.Tensor]):
    if not node_attrs:
        return []
    first = node_attrs[0]
    if isinstance(first, dict):
        if batch_vec is None or (isinstance(batch_vec, torch.Tensor) and batch_vec.numel() == 0):
            return [node_attrs]
        per_graph = []
        cursor = 0
        max_graph = int(batch_vec.max().item()) + 1 if batch_vec is not None else 0
        for g in range(max_graph):
            count = int((batch_vec == g).sum().item())
            per_graph.append(node_attrs[cursor : cursor + count])
            cursor += count
        if cursor < len(node_attrs):
            per_graph.append(node_attrs[cursor:])
        return per_graph
    return node_attrs


def group_node_types(
    node_types: torch.Tensor | Sequence[Any] | None,
    batch_vec: Optional[torch.Tensor],
    num_graphs: Optional[int] = None,
) -> List[Any]:
    if node_types is None:
        return []
    if batch_vec is None:
        return [node_types]
    if not torch.is_tensor(batch_vec):
        return [node_types]
    if batch_vec.numel() == 0:
        return [node_types]
    flat_batch = batch_vec.view(-1).to(dtype=torch.long)
    observed = int(flat_batch.max().item()) + 1 if flat_batch.numel() else 0
    graph_count = max(int(num_graphs or 0), observed)
    if graph_count <= 0:
        return [node_types]
    counts = torch.bincount(flat_batch, minlength=graph_count).tolist()
    result: List[Any] = []
    cursor = 0
    total = len(node_types)
    for count in counts:
        step = int(count)
        end = min(total, cursor + step)
        result.append(node_types[cursor:end])
        cursor = end
    if cursor < total:
        result.append(node_types[cursor:])
    return result


def _sorted_attribute_items(attr_dict: dict | None) -> List[tuple[str, Any]]:
    if not attr_dict:
        return []
    items: List[tuple[str, Any]] = []
    for key, value in attr_dict.items():
        name = attribute_key_to_name(key)
        if name in {"pin_role", "pin_slot_index"}:
            continue
        items.append((name, value))
    items.sort(key=lambda item: item[0])
    return items


def _wl_attribute_value_token(value: Any, depth: int = 0) -> str:
    """Convert heterogeneous attribute values into compact, comparable tokens."""

    max_depth = 2
    seq_preview = 8
    str_preview = 32
    if depth > max_depth:
        return "..."
    if value is None:
        return "none"
    if isinstance(value, bool) or isinstance(value, np.bool_):
        return "true" if bool(value) else "false"
    if isinstance(value, (int, float, np.integer, np.floating)):
        return f"{float(value):.4g}"
    if torch.is_tensor(value):
        if value.numel() == 0:
            return "[]"
        flat = value.detach().cpu().view(-1).tolist()
        return _wl_attribute_value_token(flat, depth)
    if isinstance(value, np.ndarray):
        if value.size == 0:
            return "[]"
        return _wl_attribute_value_token(value.reshape(-1).tolist(), depth)
    if isinstance(value, (list, tuple)):
        tokens = [_wl_attribute_value_token(v, depth + 1) for v in list(value)[:seq_preview]]
        if len(value) > seq_preview:
            tokens.append(f"+{len(value) - seq_preview}")
        return "[" + ",".join(tokens) + "]"
    if isinstance(value, dict):
        parts = []
        for key in sorted(value.keys(), key=str):
            parts.append(f"{key}:{_wl_attribute_value_token(value[key], depth + 1)}")
        return "{" + ",".join(parts) + "}"
    if isinstance(value, str):
        trimmed = value.strip()
        if len(trimmed) > str_preview:
            trimmed = trimmed[:str_preview]
        return trimmed
    return str(value)


def _wl_attribute_fingerprint(attrs: Any) -> str:
    """Stable string fingerprint for a node's attribute dictionary."""

    if attrs is None:
        return ""
    if isinstance(attrs, dict):
        combined: List[tuple[str, Any]] = list(_sorted_attribute_items(attrs))
        for meta_name in ("pin_role", "pin_slot_index"):
            if meta_name in attrs:
                combined.append((meta_name, attrs[meta_name]))
        combined.sort(key=lambda item: attribute_key_to_name(item[0]))
        parts: List[str] = []
        seen: Set[str] = set()
        for key, value in combined:
            name = attribute_key_to_name(key)
            if name in seen:
                continue
            seen.add(name)
            if name.startswith("__"):
                continue
            parts.append(f"{name}={_wl_attribute_value_token(value)}")
        return ";".join(parts)
    if isinstance(attrs, (list, tuple)):
        tokens = [_wl_attribute_value_token(value) for value in list(attrs)]
        return "[" + ",".join(tokens) + "]"
    return _wl_attribute_value_token(attrs)


def build_teacher_attr_targets(
    node_attrs: Sequence[Any], batch_vec: Optional[torch.Tensor], shared_vocab: SharedAttributeVocab
) -> List[List[List[int]]]:
    per_graph_attrs = group_node_attributes(node_attrs, batch_vec)
    sequences: List[List[List[int]]] = []
    for graph_attrs in per_graph_attrs:
        node_sequences: List[List[int]] = []
        for attrs in graph_attrs:
            attr_names = [
                name for name, _value in _sorted_attribute_items(attrs or {}) if shared_vocab.is_name_allowed(name)
            ]
            tokens = [shared_vocab.ensure_index(name) for name in attr_names]
            tokens.append(shared_vocab.eos_index)
            node_sequences.append(tokens)
        sequences.append(node_sequences)
    return sequences


def build_teacher_attr_value_targets(
    node_attrs: Sequence[Any],
    batch_vec: Optional[torch.Tensor],
    shared_vocab: SharedAttributeVocab,
    max_value_dim: int,
) -> List[List[List[torch.Tensor]]]:
    per_graph_attrs = group_node_attributes(node_attrs, batch_vec)
    sequences: List[List[List[torch.Tensor]]] = []

    def tensorize_value(value: Any) -> torch.Tensor:
        if value is None:
            tensor = torch.zeros(1, dtype=torch.float32)
        elif torch.is_tensor(value):
            tensor = value.detach().view(-1).float().cpu()
        elif isinstance(value, np.ndarray):
            tensor = torch.from_numpy(value).view(-1).float()
        elif isinstance(value, (list, tuple)):
            tensor = torch.as_tensor(value, dtype=torch.float32).view(-1)
        elif isinstance(value, (int, float, bool)):
            tensor = torch.tensor([float(value)], dtype=torch.float32)
        elif isinstance(value, str):
            index = shared_vocab.ensure_value_literal(value)
            tensor = shared_vocab.embedding.weight.detach().cpu()[index].view(-1).float()
        else:
            tensor = torch.zeros(1, dtype=torch.float32)
        if tensor.numel() == 0:
            tensor = torch.zeros(1, dtype=torch.float32)
        if max_value_dim > 0 and tensor.numel() > max_value_dim:
            tensor = tensor[:max_value_dim]
        return tensor

    for graph_attrs in per_graph_attrs:
        node_sequences: List[List[torch.Tensor]] = []
        for attrs in graph_attrs:
            attr_values: List[torch.Tensor] = []
            for name, value in _sorted_attribute_items(attrs or {}):
                if not shared_vocab.is_name_allowed(name):
                    continue
                attr_values.append(tensorize_value(value))
            node_sequences.append(attr_values)
        sequences.append(node_sequences)
    return sequences


def build_teacher_adj_targets(
    edge_index: torch.Tensor,
    batch_vec: torch.Tensor,
    per_graph_node_counts: Sequence[int],
) -> List[Optional[torch.Tensor]]:
    """Slice dense adjacency targets per graph for decoder supervision."""

    if edge_index.numel() == 0:
        return [None for _ in per_graph_node_counts]

    dense_adj = to_dense_adj(edge_index, batch_vec, max_num_nodes=None).float()
    per_graph_targets: List[Optional[torch.Tensor]] = []
    max_graphs = min(len(per_graph_node_counts), dense_adj.size(0))
    for idx in range(max_graphs):
        node_count = int(per_graph_node_counts[idx])
        if node_count <= 0:
            per_graph_targets.append(None)
            continue
        per_graph_targets.append(dense_adj[idx, :node_count, :node_count])
    for _ in range(len(per_graph_node_counts) - max_graphs):
        per_graph_targets.append(None)
    return per_graph_targets


class NodeAttributeDeepSetEncoder(nn.Module):
    """
    Permutation‐invariant encoder for a dictionary of arbitrary node attributes.
    See "Deep Sets" by Zaheer et al. at https://arxiv.org/abs/1703.06114
    """

    def __init__(
        self,
        shared_attr_vocab: SharedAttributeVocab,
        encoder_hdim: int,
        aggregator_hdim: int,
        out_dim: int,
        *,
        max_value_dim: int | None = None,
    ):
        super().__init__()
        self.shared_attr_vocab = shared_attr_vocab
        value_dim = max_value_dim or shared_attr_vocab.embedding.embedding_dim
        if value_dim <= 0:
            raise ValueError("max_value_dim must be positive")
        self.max_value_dim = int(value_dim)
        self.attr_encoder = nn.Sequential(  # phi
            nn.Linear(shared_attr_vocab.embedding.embedding_dim + self.max_value_dim, encoder_hdim),
            nn.ReLU(),
            nn.Linear(encoder_hdim, encoder_hdim),
            nn.ReLU(),
        )
        self.aggregator = nn.Sequential(  # rho
            nn.Linear(encoder_hdim, aggregator_hdim),
            nn.ReLU(),
            nn.Linear(aggregator_hdim, out_dim),
        )
        self.out_dim = out_dim

    def get_value_tensor(self, value: Any):
        if value is None:
            value = torch.zeros(1, dtype=torch.float)
        elif isinstance(value, torch.Tensor):
            # Flatten user provided tensors while preserving autograd info when possible.
            if not value.is_floating_point():
                value = value.to(torch.float)
        elif isinstance(value, np.ndarray):
            value = torch.from_numpy(value).to(torch.float)
        elif isinstance(value, (list, tuple)):
            if len(value) == 0:
                value = torch.zeros(1, dtype=torch.float)
            else:
                try:
                    value = torch.as_tensor(value, dtype=torch.float)
                except (TypeError, ValueError) as err:
                    raise TypeError(f"Unsupported attribute value type: {type(value)}") from err
        elif isinstance(value, (int, float, bool)):
            value = torch.tensor([float(value)], dtype=torch.float)
        elif isinstance(value, str):
            index = self.shared_attr_vocab.ensure_value_literal(value)
            index = torch.tensor(index, dtype=torch.long, device=self.shared_attr_vocab.embedding.weight.device)
            value = self.shared_attr_vocab.embedding(index)
        else:
            raise TypeError(f"Unsupported attribute value type: {type(value)}")
        value = value.reshape(-1)
        value = value.to(self.shared_attr_vocab.embedding.weight.device)
        if value.numel() < self.max_value_dim:
            pad_amt = self.max_value_dim - value.numel()
            return F.pad(value, (0, pad_amt), "constant", 0.0)
        else:
            return value[: self.max_value_dim]

    def forward(self, attr_dict: Dict[str, torch.Tensor]) -> torch.Tensor:
        if not attr_dict or len(attr_dict) == 0:
            return torch.zeros(self.aggregator[-1].out_features)

        phis = []
        for attr, value in sorted(
            attr_dict.items(), key=lambda item: attribute_key_to_name(item[0])
        ):  # consistent ordering
            attr_name = attribute_key_to_name(attr)
            if attr_name in {"pin_role", "pin_slot_index"}:
                continue
            if not self.shared_attr_vocab.is_name_allowed(attr_name):
                continue
            name_idx = self.shared_attr_vocab.ensure_index(attr_name)
            name_index = torch.tensor(name_idx, dtype=torch.long, device=self.shared_attr_vocab.embedding.weight.device)
            value = self.get_value_tensor(value)
            phis.append(self.attr_encoder(torch.cat([self.shared_attr_vocab.embedding(name_index), value], dim=0)))
        if not phis:
            return torch.zeros(self.aggregator[-1].out_features, device=self.shared_attr_vocab.embedding.weight.device)
        return self.aggregator(torch.stack(phis, dim=0).sum(dim=0))


class GraphEncoder(nn.Module):
    """
    Graph encoder with learnable node type embeddings, deep set encoder for node attributes and DAG attention layers.
    Outputs per-graph mu and logvar for VAE.
    """

    def __init__(
        self,
        num_node_types: int,
        attr_encoder: NodeAttributeDeepSetEncoder,
        latent_dim: int,
        hidden_dims: List[int],
        pin_role_vocab: int = 3,
        pin_role_dim: int = 2,
    ):
        super().__init__()
        self.latent_dim = latent_dim
        self.attr_encoder = attr_encoder
        attr_emb_dim = attr_encoder.out_dim
        self.node_type_embedding = nn.Embedding(num_node_types, attr_emb_dim)
        self.pin_role_embedding = nn.Embedding(pin_role_vocab, pin_role_dim)
        self.pin_role_to_index = {role: idx for idx, role in enumerate(PIN_ROLE_ORDER)}
        self.pin_role_default_index = min(self.pin_role_to_index.get(PIN_ROLE_HIDDEN, 0), pin_role_vocab - 1)
        self.convs = nn.ModuleList()
        role_dim = self.pin_role_embedding.embedding_dim
        prev_dim = attr_emb_dim * 2 + role_dim
        for h in hidden_dims:
            self.convs.append(DAGAttention(prev_dim, h))
            prev_dim = h
        # map to latent parameters
        self.lin_mu = nn.Linear(prev_dim, latent_dim)
        self.lin_logvar = nn.Linear(prev_dim, latent_dim)

    @property
    def max_value_dim(self):
        return self.attr_encoder.max_value_dim

    @property
    def shared_attr_vocab(self):
        return self.attr_encoder.shared_attr_vocab

    def _pin_role_index(self, value: Any) -> int:
        if isinstance(value, str):
            role = value.strip().lower()
            idx = self.pin_role_to_index.get(role)
            if idx is not None:
                return min(idx, self.pin_role_embedding.num_embeddings - 1)
        return self.pin_role_default_index

    def forward(self, node_types, edge_index, node_attributes, batch, num_graphs: Optional[int] = None):
        type_embedding = self.node_type_embedding(node_types)
        num_nodes = len(node_types)
        device = type_embedding.device
        attr_embedding = torch.zeros((num_nodes, self.attr_encoder.out_dim), device=device)
        role_ids = torch.full(
            (num_nodes,),
            fill_value=self.pin_role_default_index,
            dtype=torch.long,
            device=device,
        )

        per_graph_attrs = group_node_attributes(node_attributes, batch)

        cursor = 0
        for graph_attrs in per_graph_attrs:
            for attrs in graph_attrs:
                if cursor >= num_nodes:
                    warn(
                        f"Attribute encoder produced more vectors than nodes ({cursor + 1} > {num_nodes}); extras discarded"
                    )
                    break
                attr_embedding[cursor] = self.attr_encoder(attrs).to(type_embedding.device)
                if isinstance(attrs, dict):
                    raw_role = attrs.get("pin_role")
                    if raw_role is None:
                        raw_role = attrs.get("node_type")
                else:
                    raw_role = None
                role_ids[cursor] = self._pin_role_index(raw_role)
                cursor += 1
            if cursor >= num_nodes:
                break
        if cursor < num_nodes:
            if cursor == 0 and num_nodes > 0:
                warn(f"No attribute vectors generated; leaving {num_nodes} zero rows")
            elif num_nodes > 0:
                warn(
                    f"Attribute encoder produced {cursor} vectors but expected {num_nodes}; remaining filled with zeros"
                )
        role_embedding = self.pin_role_embedding(role_ids)
        x = torch.cat([type_embedding, attr_embedding, role_embedding], dim=-1)
        for conv in self.convs:
            x = conv(x, edge_index)

        if num_nodes == 0:
            pooled = x.new_zeros((0, x.size(-1)))
        else:
            pooled = global_mean_pool(x, batch)

        if num_graphs is not None:
            expected = int(num_graphs)
            current = pooled.size(0)
            if current < expected:
                pad = pooled.new_zeros((expected - current, pooled.size(1)))
                pooled = torch.cat([pooled, pad], dim=0)
            elif current > expected:
                pooled = pooled[:expected]
        x = pooled
        mu = self.lin_mu(x)
        logvar = self.lin_logvar(x)
        return mu, logvar

    def prune_latent_dims(self, kept_idx: torch.LongTensor):
        """
        Keep only the latent dims in `kept_idx` for lin_mu and lin_logvar.
        """

        def prune_lin(old):
            layer = nn.Linear(old.in_features, kept_idx.numel()).to(old.weight.device)
            layer.weight.data = old.weight.data[kept_idx]
            layer.bias.data = old.bias.data[kept_idx]
            return layer

        self.lin_mu = prune_lin(self.lin_mu)
        self.lin_logvar = prune_lin(self.lin_logvar)
        self.latent_dim = len(kept_idx)


class GraphDeconvNet(MessagePassing):

    """
    A Graph Deconvolutional Network (GDN) layer that acts as the
    transpose/inverse of a GCNConv.  It takes an input signal X of
    size [N, in_channels] on a graph with edge_index, and produces
    an output signal of size [N, out_channels], without any fixed
    max_nodes or feature‐size assumptions.
    """

    def __init__(self, in_channels: int, out_channels: int, aggr: str = "add"):
        super().__init__(aggr=aggr)
        # weight for the "transpose" convolution
        self.lin = nn.Linear(in_channels, out_channels, bias=True)
        # optional bias after aggregation
        self.bias = nn.Parameter(torch.zeros(out_channels))

    def forward(self, edge_index: torch.LongTensor, x: torch.Tensor) -> torch.Tensor:
        """
        Args:
            edge_index: LongTensor of shape [2, E] with COO edges.
            x:          FloatTensor of shape [N, in_channels] node signals.
        Returns:
            FloatTensor of shape [N, out_channels].
        """
        x = self.lin(x)  # (acts like W^T in a transposed convolution)
        # if there are no edges, skip the propagate/unpack step
        if edge_index.numel() == 0 or edge_index.shape[1] == 0:
            return F.relu(x + self.bias)  # just apply bias + activation
        row, col = edge_index
        deg = degree(col, x.size(0), dtype=x.dtype)
        out = self.propagate(
            edge_index, x=x, norm=deg.pow(0.5)[col] * deg.pow(0.5)[row]
        )  # each node collects from neighbors
        return out + self.bias

    def message(self, x_j: torch.Tensor, norm: torch.Tensor) -> torch.Tensor:
        # x_j: neighbor features [E, out_channels]
        # norm: normalization per edge [E]
        return x_j * norm.view(-1, 1)

    def update(self, aggr_out: torch.Tensor) -> torch.Tensor:
        # optional nonlinearity
        return F.relu(aggr_out)


class GraphDecoder(nn.Module):
    """
    Recurrent generation + GDN refinement.
    1) Recurrently generate node embeddings & edges (GraphRNN style).
    2) Refine embeddings via Graph Deconvolutional Nets (GDNs).
    """

    def __init__(
        self,
        num_node_types: int,
        latent_dim: int,
        shared_attr_vocab: SharedAttributeVocab,
        hidden_dim: int = 128,
        gdn_layers: int = 2,
        edge_threshold: float = 0.5,
        max_edges_per_node: int = 256,
        max_edges_per_graph: int = 1000,
        min_pin_nodes: int | None = None,
        required_input_count: int | None = None,
        required_output_slots: Sequence[int] | None = None,
        max_attr_value_dim: int = 64,
    ):
        super().__init__()
        self.shared_attr_vocab = shared_attr_vocab
        self.latent_dim = latent_dim
        # — map latent → initial Node‐RNN state
        self.node_hidden_state_init = nn.Linear(latent_dim, hidden_dim)

        # — Node‐RNN (no input, only hidden evolves)
        self.node_rnn = nn.GRUCell(input_size=0, hidden_size=hidden_dim)
        self.stop_head = nn.Linear(hidden_dim, 1)
        self.node_head = nn.Linear(hidden_dim, hidden_dim)
        self.type_head = nn.Linear(hidden_dim, num_node_types)
        self.edge_rnn = nn.GRUCell(input_size=1, hidden_size=hidden_dim)
        self.edge_head = nn.Linear(hidden_dim, 1)

        self.attr_type_rnn = nn.GRU(input_size=1, hidden_size=hidden_dim)
        self.attr_type_head = nn.Linear(hidden_dim, 1)
        self.attr_name_rnn = nn.GRU(input_size=self.shared_attr_vocab.embedding.embedding_dim, hidden_size=hidden_dim)
        self.attr_name_head = nn.Linear(hidden_dim, shared_attr_vocab.embedding.embedding_dim)
        self.attr_dims_head = nn.Linear(hidden_dim, 1)  # determine num dimensions per attr
        self.attr_val_rnn = nn.GRU(input_size=1, hidden_size=hidden_dim)
        self.attr_val_head = nn.Linear(hidden_dim, 1)  # extract value per attr dimension
        self.attr_sos_index = self.shared_attr_vocab.sos_index
        self.attr_eos_index = self.shared_attr_vocab.eos_index
        self.attr_unk_index = self.shared_attr_vocab.unk_index
        self._attr_name_cache_version = -1
        self._attr_name_vocab_size = self.shared_attr_vocab.embedding.num_embeddings
        self._attr_name_allowed_cache: Dict[int, Set[int]] = {}
        self._attr_name_invalid_cache: Dict[int, Tuple[int, ...]] = {}
        self._value_literal_cache_version = -1
        self._value_literal_indices: List[int] = []
        self._value_literal_tokens: List[str] = []

        # — GraphDeconvNet stack (learned spectral decoders)
        self.gdns = nn.ModuleList([GraphDeconvNet(hidden_dim, hidden_dim) for _ in range(gdn_layers)])
        self.max_attributes_per_node = 50
        self.max_attr_value_dim = max(1, int(max_attr_value_dim))
        self.edge_threshold = edge_threshold
        self.max_edges_per_node = max(1, int(max_edges_per_node))
        self.max_edges_per_graph = max(1, int(max_edges_per_graph))
        if min_pin_nodes is None:
            self.min_pin_nodes = 0
        else:
            try:
                self.min_pin_nodes = max(0, int(min_pin_nodes))
            except (TypeError, ValueError):
                self.min_pin_nodes = 0
        if required_input_count is None:
            self.required_input_count = 0
        else:
            try:
                self.required_input_count = max(0, int(required_input_count))
            except (TypeError, ValueError):
                self.required_input_count = 0
        self.required_output_slots: List[int] = []
        if required_output_slots:
            for slot in required_output_slots:
                try:
                    slot_int = int(slot)
                except (TypeError, ValueError):
                    continue
                if slot_int < 0:
                    continue
                self.required_output_slots.append(slot_int)

        resolved_input_slots = self._resolved_required_input_slots()
        pin_node_budget = resolved_input_slots + len(self.required_output_slots)
        if pin_node_budget <= 0:
            pin_node_budget = 1
        self._base_required_node_count = max(self.min_pin_nodes, pin_node_budget)
        self.max_nodes = max(250, self._base_required_node_count)
        # Encourage attribute decoder to terminate by progressively biasing the EOS logit.
        self.attr_eos_bias_base = 0.0
        self.attr_eos_bias_slope = 0.1
        self._min_required_nodes = self._base_required_node_count
        # Soft-stop controls to avoid hammering the hard max_nodes cap.
        self.node_stop_decay_start_ratio = 0.85  # begin decaying continue prob after ~85% of the budget
        self.node_stop_decay_margin = 16  # ensure a small grace window even for tiny budgets
        self.node_stop_decay_min = 0.02  # never drive continue prob fully to zero so the sampler can explore
        # Apply the same soft-stop strategy to edge sampling to keep graphs tractable.
        self.edge_stop_decay_start_ratio = 0.85
        self.edge_stop_decay_margin = 64
        self.edge_stop_decay_min = 0.02

    def _resolved_required_input_slots(self) -> int:
        configured = 1
        try:
            configured = max(0, int(self.required_input_count or 1))
        except (TypeError, ValueError):
            configured = 1
        fallback = 1
        try:
            fallback = max(1, int(self.min_pin_nodes or 1) - len(self.required_output_slots))
        except (TypeError, ValueError):
            fallback = 1
        return max(configured, fallback)

    def _apply_node_continue_decay(
        self,
        continue_prob: torch.Tensor,
        emitted_nodes: int,
        minimum_required_nodes: int,
    ) -> torch.Tensor:
        """Gently reduce sampling probability as the node budget is consumed."""
        if self.max_nodes <= 0:
            return continue_prob
        # Start decaying once we have emitted most of the allowed nodes but always obey the minimum.
        decay_start = int(self.max_nodes * self.node_stop_decay_start_ratio)
        decay_start = max(minimum_required_nodes, decay_start - self.node_stop_decay_margin)
        decay_start = min(decay_start, self.max_nodes)
        if emitted_nodes < decay_start:
            return continue_prob
        span = max(1, self.max_nodes - decay_start)
        distance = max(0, emitted_nodes - decay_start + 1)
        scale = 1.0 - (distance / span)
        scale = float(max(self.node_stop_decay_min, min(1.0, scale)))
        decay = continue_prob.new_full(continue_prob.shape, scale)
        adjusted = continue_prob * decay
        if self.node_stop_decay_min > 0:
            adjusted = adjusted.clamp_(self.node_stop_decay_min, 1.0)
        else:
            adjusted = adjusted.clamp_(0.0, 1.0)
        return adjusted

    def _apply_edge_continue_decay(
        self,
        edge_prob: torch.Tensor,
        emitted_edges: int,
    ) -> torch.Tensor:
        """Mirror the node soft-stop logic for edge sampling."""
        if self.max_edges_per_graph <= 0:
            return edge_prob
        decay_start = int(self.max_edges_per_graph * self.edge_stop_decay_start_ratio)
        decay_start = max(0, decay_start - self.edge_stop_decay_margin)
        decay_start = min(decay_start, self.max_edges_per_graph)
        if emitted_edges < decay_start:
            return edge_prob
        span = max(1, self.max_edges_per_graph - decay_start)
        distance = max(0, emitted_edges - decay_start + 1)
        scale = 1.0 - (distance / span)
        scale = float(max(self.edge_stop_decay_min, min(1.0, scale)))
        decay = edge_prob.new_full(edge_prob.shape, scale)
        adjusted = edge_prob * decay
        if self.edge_stop_decay_min > 0:
            adjusted = adjusted.clamp_(self.edge_stop_decay_min, 1.0)
        else:
            adjusted = adjusted.clamp_(0.0, 1.0)
        return adjusted

    def _emit_pin_debug_snapshot(self, node_attributes: List[Dict[str, Any]]) -> None:
        try:
            base = Path("debug_guided_offspring") / "pin_debug"
            base.mkdir(parents=True, exist_ok=True)
            timestamp = int(time.time() * 1000)
            path = base / f"pin_debug_{timestamp}.json"
            payload = {
                "required_inputs": self._resolved_required_input_slots(),
                "required_outputs": list(self.required_output_slots),
                "min_pin_nodes": self.min_pin_nodes,
                "node_attributes": node_attributes,
            }
            path.write_text(json.dumps(payload, indent=2, default=str))
        except Exception as exc:  # pragma: no cover - diagnostic path
            logger.exception("Failed to write pin debug snapshot: %s", exc)

    def _node_type_index_for(self, node_types: Sequence[Any], node_idx: int) -> Optional[int]:
        if node_idx >= len(node_types):
            return None
        raw = node_types[node_idx]
        if isinstance(raw, (list, tuple)):
            raw = raw[0] if raw else None
        if raw is None:
            return None
        if torch.is_tensor(raw):
            if raw.numel() == 0:
                return None
            raw = raw.view(-1)[0].item()
        try:
            value = int(raw)
        except (TypeError, ValueError):
            return None
        if value < 0:
            return None
        return value

    def _refresh_attr_name_cache(self) -> None:
        vocab_size = self.shared_attr_vocab.embedding.num_embeddings
        version = genes.ATTRIBUTE_NAMES_VERSION
        if self._attr_name_cache_version == version and self._attr_name_vocab_size == vocab_size:
            return
        self._attr_name_cache_version = version
        self._attr_name_vocab_size = vocab_size
        self._attr_name_allowed_cache.clear()
        self._attr_name_invalid_cache.clear()

    def _allowed_name_indices_for_type(self, node_type_idx: Optional[int]) -> Set[int]:
        self._refresh_attr_name_cache()
        cache_key = -1 if node_type_idx is None else int(node_type_idx)
        cached = self._attr_name_allowed_cache.get(cache_key)
        if cached is not None:
            return cached
        allowed: Set[int] = {self.attr_eos_index, self.attr_sos_index, self.attr_unk_index}
        node_type_name = None
        if node_type_idx is not None and 0 <= node_type_idx < len(genes.NODE_TYPE_OPTIONS):
            node_type_name = genes.NODE_TYPE_OPTIONS[node_type_idx]
        if node_type_name:
            for name in genes.canonical_attribute_names_for_kind(node_type_name):
                if not self.shared_attr_vocab.is_name_allowed(name):
                    continue
                idx = self.shared_attr_vocab.name_to_index.get(name)
                if idx is not None:
                    allowed.add(idx)
        for name, idx in self.shared_attr_vocab.name_to_index.items():
            if name.startswith("__"):
                allowed.add(idx)
        self._attr_name_allowed_cache[cache_key] = allowed
        vocab_size = self.shared_attr_vocab.embedding.num_embeddings
        invalid = tuple(i for i in range(vocab_size) if i not in allowed)
        self._attr_name_invalid_cache[cache_key] = invalid
        return allowed

    def _is_name_allowed_for_type(self, node_type_idx: Optional[int], name_index: int) -> bool:
        allowed = self._allowed_name_indices_for_type(node_type_idx)
        return name_index in allowed

    def _mask_logits_for_type(self, node_type_idx: Optional[int], logits: torch.Tensor) -> torch.Tensor:
        if logits.numel() == 0:
            return logits
        self._allowed_name_indices_for_type(node_type_idx)
        cache_key = -1 if node_type_idx is None else int(node_type_idx)
        invalid = self._attr_name_invalid_cache.get(cache_key)
        if not invalid:
            return logits
        invalid_idx = torch.as_tensor(invalid, dtype=torch.long, device=logits.device)
        mask_value = torch.finfo(logits.dtype).min if torch.is_floating_point(logits) else -1e9
        masked = logits.clone()
        masked.index_fill_(0, invalid_idx, mask_value)
        return masked

    def _refresh_value_literal_cache(self) -> None:
        vocab_size = self.shared_attr_vocab.embedding.num_embeddings
        if self._value_literal_cache_version == vocab_size:
            return
        prefix = self.shared_attr_vocab.VALUE_LITERAL_PREFIX
        indices: List[int] = []
        tokens: List[str] = []
        for name, idx in self.shared_attr_vocab.name_to_index.items():
            if name.startswith(prefix):
                indices.append(idx)
                tokens.append(name)
        self._value_literal_indices = indices
        self._value_literal_tokens = tokens
        self._value_literal_cache_version = vocab_size

    def _materialize_string_literal(self, value_tensor: torch.Tensor) -> Optional[str]:
        self._refresh_value_literal_cache()
        if not self._value_literal_indices:
            return None
        embeddings = self.shared_attr_vocab.embedding.weight.detach().cpu()
        literal_vectors = embeddings[self._value_literal_indices]
        if literal_vectors.numel() == 0:
            return None
        dim = literal_vectors.size(1)
        target = value_tensor.detach().cpu().view(-1)
        if dim <= 0:
            return None
        if target.numel() < dim:
            pad = torch.zeros(dim - target.numel())
            target = torch.cat([target, pad])
        elif target.numel() > dim:
            target = target[:dim]
        diffs = literal_vectors - target.unsqueeze(0)
        distances = torch.sum(diffs * diffs, dim=1)
        best = int(torch.argmin(distances).item())
        token = self._value_literal_tokens[best]
        prefix = self.shared_attr_vocab.VALUE_LITERAL_PREFIX
        if token.startswith(prefix):
            return token[len(prefix) :]
        return token

    def _flatten_attr_value_cells(self, value_cells: Any) -> torch.Tensor:
        if value_cells is None:
            return torch.zeros(0, dtype=torch.float32)
        if torch.is_tensor(value_cells):
            tensor = value_cells.detach()
            if not torch.is_floating_point(tensor):
                tensor = tensor.to(dtype=torch.float32)
            else:
                tensor = tensor.float()
            return tensor.view(-1).cpu()
        if isinstance(value_cells, np.ndarray):
            if value_cells.size == 0:
                return torch.zeros(0, dtype=torch.float32)
            return torch.from_numpy(value_cells).view(-1).float()
        if isinstance(value_cells, (bool, int, float)):
            return torch.tensor([float(value_cells)], dtype=torch.float32)
        if isinstance(value_cells, (list, tuple)):
            flattened: List[torch.Tensor] = []
            for cell in value_cells:
                tensor = self._flatten_attr_value_cells(cell)
                if tensor.numel() > 0:
                    flattened.append(tensor)
            if flattened:
                return torch.cat(flattened)
            return torch.zeros(0, dtype=torch.float32)
        return torch.zeros(0, dtype=torch.float32)

    def _materialize_attribute_value(self, value_cells: Any, value_kind: Optional[str]) -> Any:
        flat = self._flatten_attr_value_cells(value_cells)
        if flat.numel() == 0:
            return None
        kind = (value_kind or "").strip().lower()
        if kind.startswith("list"):
            inner_kind = None
            if kind.startswith("list[") and kind.endswith("]"):
                inner_kind = kind[5:-1].strip() or None
            values: List[Any] = []
            for scalar in flat.view(-1):
                values.append(self._materialize_attribute_value(scalar.view(1), inner_kind))
            return values
        scalar = float(flat.view(-1)[0].item())
        if kind == "bool":
            return bool(scalar >= 0.5)
        if kind == "int":
            return int(round(scalar))
        if kind in {"float", "scalar", "number"}:
            return float(scalar)
        if kind == "string":
            literal = self._materialize_string_literal(flat)
            if literal is not None:
                return literal
        if kind == "tensor":
            return flat.clone()
        if flat.numel() == 1:
            return float(scalar)
        return flat.clone()

    def _enforce_required_pin_metadata(self, node_attributes: List[Dict[str, Any]]):
        if not node_attributes:
            logger.warning("No node_attributes passed")
            return
        total = len(node_attributes)
        required_inputs = self._resolved_required_input_slots()
        expected_nodes = max(self._min_required_nodes, required_inputs + len(self.required_output_slots))
        if total < expected_nodes:
            logger.warning(
                "Decoder emitted fewer nodes than required before pin enforcement | total=%d expected=%d required_inputs=%d required_outputs=%d min_pin_nodes=%d",
                total,
                expected_nodes,
                required_inputs,
                len(self.required_output_slots),
                self.min_pin_nodes,
            )
        input_slots = min(required_inputs, total)
        for slot in range(input_slots):
            attrs = node_attributes[slot]
            if not isinstance(attrs, dict):
                attrs = {}
            attrs["pin_role"] = PIN_ROLE_INPUT
            attrs["pin_slot_index"] = slot
            node_attributes[slot] = attrs
        if total <= input_slots:
            logger.warning(
                "Insufficient node count | total=%d required_inputs=%d required_outputs=%d min_pin_nodes=%d",
                total,
                required_inputs,
                len(self.required_output_slots),
                self.min_pin_nodes,
            )
            self._emit_pin_debug_snapshot(node_attributes)
            return
        available_indices = [idx for idx in range(total) if idx >= input_slots]
        for slot in self.required_output_slots:
            if not available_indices:
                logger.warning(
                    "Insufficient node count | total=%d required_inputs=%d required_outputs=%d min_pin_nodes=%d",
                    total,
                    required_inputs,
                    len(self.required_output_slots),
                    self.min_pin_nodes,
                )
                self._emit_pin_debug_snapshot(node_attributes)
                break
            idx = available_indices.pop(0)
            attrs = node_attributes[idx]
            if not isinstance(attrs, dict):
                attrs = {}
            attrs["pin_role"] = PIN_ROLE_OUTPUT
            attrs["pin_slot_index"] = int(slot)
            node_attributes[idx] = attrs

    def forward(
        self,
        latent,
        teacher_attr_targets: Optional[List[List[List[int]]]] = None,
        teacher_adj_targets: Optional[List[Optional[torch.Tensor]]] = None,
        teacher_attr_value_targets: Optional[List[List[List[torch.Tensor]]]] = None,
        teacher_node_types: Optional[List[Any]] = None,
    ):
        """
        (num_graphs, latent_dim)
        returns: list of graphs, each {'node_types': LongTensor[1, N],
                                       'node_attributes': List[{name: attribute_value} x N],
                                       'edge_index': LongTensor[2, E]}
        teacher_node_types: per-graph sequences of ground-truth node type indices used to
                            optionally disable attribute supervision when the predicted type
                            does not match the teacher type.
        """
        _forward_prof = torch.autograd.profiler.record_function("GraphDecoder.forward")
        _forward_prof.__enter__()
        try:
            device = latent.device
            all_graphs = []
            attr_teacher_loss = latent.new_tensor(0.0)
            attr_teacher_tokens = 0
            attr_value_teacher_loss = latent.new_tensor(0.0)
            attr_value_teacher_tokens = 0
            attr_dim_teacher_loss = latent.new_tensor(0.0)
            attr_dim_teacher_tokens = 0
            node_teacher_loss = latent.new_tensor(0.0)
            node_teacher_tokens = 0
            edge_teacher_loss = latent.new_tensor(0.0)
            edge_teacher_tokens = 0
            attr_type_mismatch_skips = 0
            required_input_slots = self._resolved_required_input_slots()
            if teacher_attr_targets is not None:
                # ensure caps accommodate teacher supervision
                max_teacher_nodes = 0
                max_teacher_attrs = 0
                for graph_targets in teacher_attr_targets:
                    max_teacher_nodes = max(max_teacher_nodes, len(graph_targets))
                    for node_seq in graph_targets:
                        if node_seq:
                            # sequences include EOS token; actual attribute count is len - 1
                            max_teacher_attrs = max(max_teacher_attrs, max(len(node_seq) - 1, 0))

            def make_name_input(token_idx: int) -> torch.Tensor:
                token_tensor = torch.tensor([token_idx], dtype=torch.long, device=device)
                return self.shared_attr_vocab.embedding(token_tensor).view(1, 1, -1)

            with torch.autograd.profiler.record_function("GraphDecoder.graph_loop"):
                for l in range(latent.size(0)):
                    decode_stats = None
                    if DEBUG_DECODER:
                        decode_stats = {
                            "graph_index": l,
                            "node_start": time.perf_counter(),
                            "node_loop_exit": None,
                            "node_stop_samples": [],
                            "attr_events": [],
                        }
                    graph_teacher_targets = None
                    target_node_count = None
                    if teacher_attr_targets is not None and l < len(teacher_attr_targets):
                        graph_teacher_targets = teacher_attr_targets[l]
                        if graph_teacher_targets is not None:
                            target_node_count = len(graph_teacher_targets)
                    graph_value_targets = None
                    if teacher_attr_value_targets is not None and l < len(teacher_attr_value_targets):
                        graph_value_targets = teacher_attr_value_targets[l]
                    graph_adj_target = None
                    if teacher_adj_targets is not None and l < len(teacher_adj_targets):
                        graph_adj_target = teacher_adj_targets[l]
                        if graph_adj_target is not None:
                            graph_adj_target = graph_adj_target.to(device)
                            if target_node_count is None:
                                target_node_count = int(graph_adj_target.size(0))
                    graph_node_type_targets = None
                    if teacher_node_types is not None and l < len(teacher_node_types):
                        graph_node_type_targets = teacher_node_types[l]
                    if target_node_count is not None:
                        target_node_count = max(1, int(target_node_count))
                    try:
                        latent_norm = float(latent[l].detach().norm().item())
                    except Exception:
                        latent_norm = float("nan")
                    logger.debug("Decoder graph %d start | latent_norm=%.4f", l, latent_norm)
                    hidden_node = F.relu(self.node_hidden_state_init(latent[l])).unsqueeze(0)  # (hidden_dim,)
                    node_embeddings = []
                    edges = []
                    node_types = []
                    t = 0
                    node_loop_timer = time.perf_counter()
                    node_loop_iters = 0
                    hit_max_nodes_cap = False
                    hit_max_edges_cap = False
                    max_edges_per_graph = max(0, int(self.max_edges_per_graph))
                    if max_edges_per_graph == 0:
                        hit_max_edges_cap = True
                    teacher_force_nodes = self.training and (target_node_count is not None)
                    forced_pin_roles: List[str | None] = []
                    forced_pin_slots: List[int | None] = []
                    output_slot_index = 0
                    minimum_required_nodes = max(
                        self._min_required_nodes,
                        required_input_slots + len(self.required_output_slots),
                        1,
                    )

                    def ensure_output_reachable(node_idx: int, forced_role: str | None, node_edge_budget: int) -> int:
                        nonlocal edges, hit_max_edges_cap
                        if forced_role != PIN_ROLE_OUTPUT or node_edge_budget > 0:
                            return node_edge_budget
                        if node_edge_budget >= self.max_edges_per_node:
                            return node_edge_budget
                        if len(edges) >= max_edges_per_graph:
                            hit_max_edges_cap = True
                            return node_edge_budget
                        fallback_src: int | None = None
                        # Prefer the most recently emitted non-output node.
                        previous_limit = min(len(forced_pin_roles), node_idx)
                        for prev_idx in range(previous_limit - 1, -1, -1):
                            if forced_pin_roles[prev_idx] != PIN_ROLE_OUTPUT:
                                fallback_src = prev_idx
                                break
                        if fallback_src is None and required_input_slots > 0:
                            candidate = required_input_slots - 1
                            if candidate >= 0 and candidate != node_idx:
                                fallback_src = candidate
                        if fallback_src is None and node_idx > 0:
                            fallback_src = node_idx - 1
                        if fallback_src is None or fallback_src == node_idx:
                            return node_edge_budget
                        edges.append([fallback_src, node_idx])
                        return node_edge_budget + 1

                    stop_target_node_count = target_node_count
                    if teacher_force_nodes and stop_target_node_count is not None:
                        if stop_target_node_count < minimum_required_nodes:
                            if DEBUG_DECODER and decode_stats is not None:
                                decode_stats.setdefault("node_loop_notes", []).append(
                                    {
                                        "event": "bump_teacher_target",
                                        "requested": int(stop_target_node_count),
                                        "enforced": int(minimum_required_nodes),
                                    }
                                )
                            stop_target_node_count = minimum_required_nodes
                    with torch.autograd.profiler.record_function("GraphDecoder.node_loop"):
                        while True:
                            logger.debug(f"Decoding node {t}")
                            node_loop_iters += 1
                            if t > self.max_nodes:
                                hit_max_nodes_cap = True
                                logger.warning("max nodes reached")
                                if DEBUG_DECODER and decode_stats is not None:
                                    decode_stats["node_loop_exit"] = decode_stats["node_loop_exit"] or "max_nodes_pre"
                                break
                            hidden_node = self.node_rnn(
                                torch.zeros(hidden_node.shape[0], 0, device=device), hidden_node
                            )

                            stop_logit = self.stop_head(hidden_node)
                            stop_prob = torch.sigmoid(stop_logit)
                            stop_prob = torch.nan_to_num(stop_prob, nan=1.0).clamp(0.0, 1.0)
                            continue_prob = (1.0 - stop_prob).clamp(0.0, 1.0)
                            force_minimum_nodes = t < minimum_required_nodes
                            if teacher_force_nodes:
                                target_stop = (
                                    1.0 if (stop_target_node_count is not None and t >= stop_target_node_count) else 0.0
                                )
                                node_teacher_loss = node_teacher_loss + F.binary_cross_entropy_with_logits(
                                    stop_logit, torch.full_like(stop_logit, target_stop)
                                )
                                node_teacher_tokens += 1
                                if target_stop >= 0.5 and not force_minimum_nodes:
                                    if DEBUG_DECODER and decode_stats is not None:
                                        decode_stats["node_loop_exit"] = (
                                            decode_stats["node_loop_exit"] or "teacher_nodes"
                                        )
                                    break
                            else:
                                if force_minimum_nodes:
                                    continue_prob = torch.ones_like(continue_prob)
                                else:
                                    continue_prob = self._apply_node_continue_decay(
                                        continue_prob,
                                        emitted_nodes=t,
                                        minimum_required_nodes=minimum_required_nodes,
                                    )
                                if DEBUG_DECODER and decode_stats is not None:
                                    decode_stats["node_stop_samples"].append(float(continue_prob.item()))
                                if torch.bernoulli(continue_prob).item() == 0:
                                    if t == 0:
                                        continue_prob = torch.ones_like(continue_prob)
                                    else:
                                        break
                            if t > self.max_nodes:
                                hit_max_nodes_cap = True
                                logger.warning("max nodes reached")
                                if DEBUG_DECODER and decode_stats is not None:
                                    decode_stats["node_loop_exit"] = decode_stats["node_loop_exit"] or "max_nodes_post"
                                break
                            new_node = self.node_head(hidden_node).squeeze(0)
                            node_embeddings.append(new_node)
                            node_types.append(self.type_head(new_node).argmax(dim=-1).cpu().tolist())

                            node_index = t
                            forced_role = None
                            forced_slot = None
                            if required_input_slots and node_index < required_input_slots:
                                forced_role = PIN_ROLE_INPUT
                                forced_slot = node_index
                            elif output_slot_index < len(self.required_output_slots):
                                forced_role = PIN_ROLE_OUTPUT
                                forced_slot = self.required_output_slots[output_slot_index]
                                output_slot_index += 1
                            forced_pin_roles.append(forced_role)
                            forced_pin_slots.append(forced_slot)
                            hidden_edge = hidden_node
                            edge_in = torch.zeros(1, 1, device=device)
                            node_edge_budget = 0
                            total_edge_budget = len(edges)
                            for i in range(node_index):
                                if node_edge_budget >= self.max_edges_per_node:
                                    break
                                if total_edge_budget >= max_edges_per_graph:
                                    hit_max_edges_cap = True
                                    break
                                hidden_edge = self.edge_rnn(edge_in, hidden_edge)
                                edge_logit = self.edge_head(hidden_edge).view(-1)
                                p_edge = torch.sigmoid(edge_logit)
                                p_edge = torch.nan_to_num(p_edge, nan=0.0).clamp(0.0, 1.0)
                                if teacher_force_nodes and graph_adj_target is not None:
                                    if i < graph_adj_target.size(0) and node_index < graph_adj_target.size(1):
                                        target_edge = graph_adj_target[i, node_index].view(-1)
                                        edge_teacher_loss = edge_teacher_loss + F.binary_cross_entropy_with_logits(
                                            edge_logit, target_edge
                                        )
                                        edge_teacher_tokens += 1
                                if teacher_force_nodes:
                                    edge_active = bool((p_edge > self.edge_threshold).item())
                                else:
                                    sample_prob = self._apply_edge_continue_decay(
                                        p_edge,
                                        emitted_edges=total_edge_budget,
                                    )
                                    edge_sample = torch.bernoulli(sample_prob)
                                    edge_active = bool(edge_sample.item())
                                if edge_active:
                                    edges.append([i, node_index])
                                    node_edge_budget += 1
                                    total_edge_budget += 1
                                edge_in = p_edge.unsqueeze(0)

                            node_edge_budget = ensure_output_reachable(node_index, forced_role, node_edge_budget)

                            t = node_index + 1
                            if DEBUG_DECODER and t % 50 == 0:
                                elapsed = time.perf_counter() - node_loop_timer
                                logger.info(
                                    "Decoder graph %d node generation progress: %d nodes (max=%d) elapsed=%.2fs",
                                    decode_stats["graph_index"],
                                    t,
                                    self.max_nodes,
                                    elapsed,
                                )
                            if DEBUG_DECODER and node_loop_iters % 200 == 0:
                                logger.info(
                                    "Decoder graph %d node loop iterations=%d (nodes=%d)",
                                    decode_stats["graph_index"],
                                    node_loop_iters,
                                    t,
                                )

            while len(node_embeddings) < minimum_required_nodes:
                logger.debug(
                    "Forcing additional node to satisfy minimum pin quota | current=%d required=%d",
                    len(node_embeddings),
                    minimum_required_nodes,
                )
                node_loop_iters += 1
                hidden_node = self.node_rnn(torch.zeros(hidden_node.shape[0], 0, device=device), hidden_node)
                stop_logit = self.stop_head(hidden_node)
                stop_prob = torch.sigmoid(stop_logit)
                stop_prob = torch.nan_to_num(stop_prob, nan=1.0).clamp(0.0, 1.0)
                continue_prob = (1.0 - stop_prob).clamp(0.0, 1.0)
                if DEBUG_DECODER and decode_stats is not None:
                    decode_stats["node_stop_samples"].append(float(continue_prob.item()))
                new_node = self.node_head(hidden_node).squeeze(0)
                node_embeddings.append(new_node)
                node_types.append(self.type_head(new_node).argmax(dim=-1).cpu().tolist())
                node_index = len(node_embeddings) - 1
                forced_role = None
                forced_slot = None
                if required_input_slots and node_index < required_input_slots:
                    forced_role = PIN_ROLE_INPUT
                    forced_slot = node_index
                elif output_slot_index < len(self.required_output_slots):
                    forced_role = PIN_ROLE_OUTPUT
                    forced_slot = self.required_output_slots[output_slot_index]
                    output_slot_index += 1
                forced_pin_roles.append(forced_role)
                forced_pin_slots.append(forced_slot)
                hidden_edge = hidden_node
                edge_in = torch.zeros(1, 1, device=device)
                node_edge_budget = 0
                total_edge_budget = len(edges)
                for i in range(node_index):
                    if node_edge_budget >= self.max_edges_per_node:
                        break
                    if total_edge_budget >= max_edges_per_graph:
                        hit_max_edges_cap = True
                        break
                    hidden_edge = self.edge_rnn(edge_in, hidden_edge)
                    edge_logit = self.edge_head(hidden_edge).view(-1)
                    p_edge = torch.sigmoid(edge_logit)
                    p_edge = torch.nan_to_num(p_edge, nan=0.0).clamp(0.0, 1.0)
                    sample_prob = self._apply_edge_continue_decay(
                        p_edge,
                        emitted_edges=total_edge_budget,
                    )
                    edge_sample = torch.bernoulli(sample_prob)
                    edge_active = bool(edge_sample.item())
                    if edge_active:
                        edges.append([i, node_index])
                        node_edge_budget += 1
                        total_edge_budget += 1
                    edge_in = p_edge.unsqueeze(0)

                node_edge_budget = ensure_output_reachable(node_index, forced_role, node_edge_budget)

            if len(node_embeddings) < minimum_required_nodes:
                logger.warning(
                    "Node loop exited below requirement | nodes=%d required=%d teacher_force=%s target_node_count=%s",
                    len(node_embeddings),
                    minimum_required_nodes,
                    bool(teacher_force_nodes),
                    stop_target_node_count,
                )

            if node_embeddings:
                node_embeddings = torch.stack(node_embeddings, dim=0)
                edges = torch.tensor(edges, dtype=torch.long).t().contiguous()
            else:
                node_embeddings = torch.zeros((0, self.node_head.out_features), device=device)
                edges = torch.zeros((2, 0), dtype=torch.long, device=device)

            expected_nodes = max(self._min_required_nodes, required_input_slots + len(self.required_output_slots), 1)
            if node_embeddings.size(0) < expected_nodes:
                logger.warning(
                    "Padding decoder output to expected node count | nodes=%d expected=%d",
                    node_embeddings.size(0),
                    expected_nodes,
                )
                pad = expected_nodes - node_embeddings.size(0)
                pad_tensor = torch.zeros((pad, node_embeddings.size(1)), device=node_embeddings.device)
                node_embeddings = torch.cat([node_embeddings, pad_tensor], dim=0)
                node_types.extend([0] * pad)

            if DEBUG_DECODER:
                decode_stats["node_time"] = time.perf_counter() - decode_stats["node_start"]
                exit_reason = decode_stats["node_loop_exit"] or "stop"
                stop_samples = decode_stats["node_stop_samples"]
                avg_p_stop = float(sum(stop_samples) / len(stop_samples)) if stop_samples else float("nan")
                last_p_stop = stop_samples[-1] if stop_samples else float("nan")
                logger.info(
                    "Decoder graph %d node loop exit=%s nodes=%d max=%d iters=%d avg_p_stop=%.4f last_p_stop=%.4f",
                    decode_stats["graph_index"],
                    exit_reason,
                    node_embeddings.size(0),
                    self.max_nodes,
                    node_loop_iters,
                    avg_p_stop,
                    last_p_stop,
                )
                decode_stats["attr_start"] = time.perf_counter()
                decode_stats["node_count"] = int(node_embeddings.size(0))
                decode_stats["edge_count"] = int(edges.size(1)) if edges.numel() > 0 else 0
                decode_stats["attr_nodes"] = 0
                decode_stats["attr_iters"] = 0
                decode_stats["attr_value_cells"] = 0

            # refine via graph deconvolution
            for gdn in self.gdns:
                node_embeddings = gdn(edges, node_embeddings)

            node_attributes = []
            for node_idx, embedding in enumerate(node_embeddings):
                if DEBUG_DECODER:
                    decode_stats["attr_nodes"] += 1
                attrs = {}
                # Order-based assignment derived from emission index.
                order_role = None
                order_slot = None
                if node_idx < len(forced_pin_roles):
                    order_role = forced_pin_roles[node_idx]
                if node_idx < len(forced_pin_slots):
                    order_slot = forced_pin_slots[node_idx]

                if order_role is not None:
                    attrs["pin_role"] = order_role
                if order_slot is not None:
                    attrs["pin_slot_index"] = order_slot
                name_hidden = embedding.unsqueeze(0).unsqueeze(0)
                val_hidden = None
                t = 0
                attr_loop_iters = 0
                used_name_indices: Set[int] = set()
                node_teacher_targets: Optional[List[int]] = None
                node_value_targets: Optional[List[torch.Tensor]] = None
                attr_exit_reason = "eos"
                last_attr_logits: Optional[Tuple[float, float, int]] = None
                if graph_teacher_targets is not None and node_idx < len(graph_teacher_targets):
                    node_teacher_targets = graph_teacher_targets[node_idx] or None
                if graph_value_targets is not None and node_idx < len(graph_value_targets):
                    node_value_targets = graph_value_targets[node_idx] or None
                node_type_idx = self._node_type_index_for(node_types, node_idx)
                teacher_type_idx = None
                if graph_node_type_targets is not None:
                    teacher_type_idx = self._node_type_index_for(graph_node_type_targets, node_idx)
                if (
                    teacher_type_idx is not None
                    and node_teacher_targets
                    and (node_type_idx is None or teacher_type_idx != node_type_idx)
                ):
                    node_teacher_targets = None
                    node_value_targets = None
                    attr_type_mismatch_skips += 1

                def project_name_logits(name_out: torch.Tensor) -> torch.Tensor:
                    return self.attr_name_head(name_out).reshape(-1)

                def add_attribute(name_index: int, name: str, target_value: Optional[torch.Tensor] = None):
                    nonlocal t, attr_value_teacher_loss, attr_value_teacher_tokens, attr_dim_teacher_loss, attr_dim_teacher_tokens
                    if name in ("pin_role", "pin_slot_index"):
                        return False
                    raw_dim = self.attr_dims_head(embedding).squeeze()
                    raw_dim = torch.nan_to_num(raw_dim, nan=0.0, posinf=20.0, neginf=-20.0)
                    dim_val = F.softplus(raw_dim)
                    dim_val = torch.nan_to_num(dim_val, nan=1.0, posinf=float(self.max_attr_value_dim), neginf=1.0)
                    attr_dims_target = None
                    if target_value is not None:
                        target_vector = target_value.to(device).view(-1)
                        if target_vector.numel() == 0:
                            target_vector = torch.zeros(1, device=device)
                        target_vector = target_vector[: self.max_attr_value_dim]
                        attr_dims_target = int(target_vector.numel())
                    else:
                        target_vector = None
                    attr_dims = int(torch.clamp(dim_val, min=1.0, max=float(self.max_attr_value_dim)).item())
                    attr_dims = max(1, min(attr_dims, self.max_attr_value_dim))
                    if attr_dims_target is not None:
                        attr_dims = max(1, min(attr_dims_target, self.max_attr_value_dim))
                        target_tensor = torch.tensor([float(attr_dims_target)], device=device)
                        attr_dim_teacher_loss = attr_dim_teacher_loss + F.mse_loss(dim_val.reshape(1), target_tensor)
                        attr_dim_teacher_tokens += 1
                    values = []
                    value_hidden = embedding.unsqueeze(0).unsqueeze(1)
                    value_input = torch.zeros(1, 1, 1, device=device)
                    for dim_idx in range(attr_dims):
                        value_out, value_hidden = self.attr_val_rnn(value_input, value_hidden)
                        v = self.attr_val_head(value_out).view(-1)
                        if target_vector is not None and dim_idx < target_vector.numel():
                            target_scalar = target_vector[dim_idx].view(-1)
                            attr_value_teacher_loss = attr_value_teacher_loss + F.mse_loss(v, target_scalar.to(device))
                            attr_value_teacher_tokens += 1
                            next_input = target_scalar.view(1, 1, 1).to(device)
                        else:
                            next_input = v.unsqueeze(0).unsqueeze(-1)
                        values.append(v)
                        value_input = next_input
                    if DEBUG_DECODER:
                        decode_stats["attr_value_cells"] += attr_dims
                        if attr_dims >= self.max_attr_value_dim:
                            logger.info(
                                "Decoder graph %d node %d attribute %s clamped to max dims (%d)",
                                decode_stats["graph_index"],
                                node_idx,
                                name,
                                self.max_attr_value_dim,
                            )
                    if name in attrs:
                        warn(name + " is already defined for currently decoding node")
                        return False
                    attrs[name] = torch.stack(values)
                    t += 1
                    used_name_indices.add(name_index)
                    if DEBUG_DECODER and (t % 25 == 0):
                        logger.info(
                            "Decoder graph %d node %d attr_count=%d",
                            decode_stats["graph_index"],
                            node_idx,
                            t,
                        )
                    return True

                with torch.autograd.profiler.record_function("GraphDecoder.attr_loop"):
                    if node_teacher_targets:
                        prev_token_idx = self.attr_sos_index
                        value_target_idx = 0
                        for target_idx in node_teacher_targets:
                            attr_loop_iters += 1
                            if DEBUG_DECODER and attr_loop_iters % 50 == 0:
                                logger.info(
                                    "Decoder graph %d node %d attr_name iterations=%d",
                                    decode_stats["graph_index"],
                                    node_idx,
                                    attr_loop_iters,
                                )
                            if t > self.max_attributes_per_node:
                                warn("max attributes per node reached")
                                attr_exit_reason = "max_attr_teacher"
                                if DEBUG_DECODER:
                                    eos_logit = float("nan") if last_attr_logits is None else last_attr_logits[0]
                                    top_logit = float("nan") if last_attr_logits is None else last_attr_logits[1]
                                    top_idx = -1 if last_attr_logits is None else last_attr_logits[2]
                                    teacher_len = len(node_teacher_targets) if node_teacher_targets else 0
                                    logger.info(
                                        "Decoder graph %d node %d attr loop hit teacher cap | attrs=%d of %d | last_eos=%.3f last_max=%.3f last_idx=%d",
                                        decode_stats["graph_index"],
                                        node_idx,
                                        t,
                                        teacher_len,
                                        eos_logit,
                                        top_logit,
                                        top_idx,
                                    )
                                break
                            name_input = make_name_input(prev_token_idx)
                            name_out, name_hidden = self.attr_name_rnn(name_input, name_hidden)
                            if DEBUG_DECODER:
                                decode_stats["attr_iters"] += 1
                            similarity_logits = torch.matmul(
                                self.shared_attr_vocab.embedding.weight,
                                project_name_logits(name_out),
                            )
                            similarity_logits = self._mask_logits_for_type(node_type_idx, similarity_logits)
                            if DEBUG_DECODER:
                                top_logit, top_idx = torch.max(similarity_logits, dim=0)
                                last_attr_logits = (
                                    float(similarity_logits[self.attr_eos_index].item()),
                                    float(top_logit.item()),
                                    int(top_idx.item()),
                                )
                            eos_bias = self.attr_eos_bias_base + self.attr_eos_bias_slope * t
                            similarity_logits[self.attr_eos_index] = similarity_logits[self.attr_eos_index] + eos_bias
                            target_tensor = torch.tensor([target_idx], dtype=torch.long, device=device)
                            if attr_teacher_loss is not None:
                                step_loss = F.cross_entropy(
                                    similarity_logits.unsqueeze(0), target_tensor, reduction="mean"
                                )
                                attr_teacher_loss = attr_teacher_loss + step_loss
                                attr_teacher_tokens += 1
                            prev_token_idx = target_idx
                            if target_idx == self.attr_eos_index:
                                break
                            name = self.shared_attr_vocab.index_to_name.get(target_idx)
                            if name is None:
                                continue
                            if not self._is_name_allowed_for_type(node_type_idx, target_idx):
                                continue
                            target_idx = self.shared_attr_vocab.ensure_index(name)
                            target_tensor = None
                            if node_value_targets and value_target_idx < len(node_value_targets):
                                target_tensor = node_value_targets[value_target_idx]
                            added = add_attribute(target_idx, name, target_tensor)
                            if added:
                                value_target_idx += 1
                    else:
                        prev_token_idx = self.attr_sos_index
                        while True:
                            attr_loop_iters += 1
                            if DEBUG_DECODER and attr_loop_iters % 50 == 0:
                                logger.info(
                                    "Decoder graph %d node %d attr_name iterations=%d",
                                    decode_stats["graph_index"],
                                    node_idx,
                                    attr_loop_iters,
                                )
                            if t > self.max_attributes_per_node:
                                warn("max attributes per node reached")
                                attr_exit_reason = "max_attr_sampling"
                                if DEBUG_DECODER:
                                    eos_logit = float("nan") if last_attr_logits is None else last_attr_logits[0]
                                    top_logit = float("nan") if last_attr_logits is None else last_attr_logits[1]
                                    top_idx = -1 if last_attr_logits is None else last_attr_logits[2]
                                    logger.info(
                                        "Decoder graph %d node %d attr loop hit sampling cap | attrs=%d | last_eos=%.3f last_max=%.3f last_idx=%d",
                                        decode_stats["graph_index"],
                                        node_idx,
                                        t,
                                        eos_logit,
                                        top_logit,
                                        top_idx,
                                    )
                                break
                            name_input = make_name_input(prev_token_idx)
                            name_out, name_hidden = self.attr_name_rnn(name_input, name_hidden)
                            if DEBUG_DECODER:
                                decode_stats["attr_iters"] += 1
                            similarity_logits = torch.matmul(
                                self.shared_attr_vocab.embedding.weight,
                                project_name_logits(name_out),
                            )
                            similarity_logits = self._mask_logits_for_type(node_type_idx, similarity_logits)
                            if DEBUG_DECODER:
                                top_logit, top_idx = torch.max(similarity_logits, dim=0)
                                last_attr_logits = (
                                    float(similarity_logits[self.attr_eos_index].item()),
                                    float(top_logit.item()),
                                    int(top_idx.item()),
                                )
                            if used_name_indices:
                                used_idx_tensor = torch.tensor(
                                    list(used_name_indices), device=similarity_logits.device, dtype=torch.long
                                )
                                similarity_logits.index_fill_(0, used_idx_tensor, -1e4)
                            eos_bias = self.attr_eos_bias_base + self.attr_eos_bias_slope * t
                            similarity_logits[self.attr_eos_index] = similarity_logits[self.attr_eos_index] + eos_bias
                            name_index = int(similarity_logits.argmax().item())
                            prev_token_idx = name_index
                            if name_index == self.attr_eos_index:
                                break
                            elif name_index == self.attr_unk_index:
                                attr_exit_reason = "unknown_token"
                                break
                            else:
                                name = self.shared_attr_vocab.index_to_name.get(name_index)
                                if name is None or not self._is_name_allowed_for_type(node_type_idx, name_index):
                                    continue
                                name_index = self.shared_attr_vocab.ensure_index(name)
                                if name in attrs:
                                    continue

                            # pin_role has already been added to the node attributes in the graph_dict
                            if name in ("pin_role", "pin_slot_index"):
                                continue

                            add_attribute(name_index, name)
                node_attributes.append(attrs)
                if DEBUG_DECODER:
                    teacher_len = len(node_teacher_targets) if node_teacher_targets else 0
                    eos_logit = float("nan") if last_attr_logits is None else last_attr_logits[0]
                    top_logit = float("nan") if last_attr_logits is None else last_attr_logits[1]
                    top_idx = -1 if last_attr_logits is None else last_attr_logits[2]
                    decode_stats["attr_events"].append(
                        {
                            "node_idx": node_idx,
                            "exit_reason": attr_exit_reason,
                            "attr_count": t,
                            "teacher_len": teacher_len,
                            "last_eos_logit": eos_logit,
                            "last_top_logit": top_logit,
                            "last_top_idx": top_idx,
                        }
                    )
                    if attr_exit_reason.startswith("max_attr"):
                        logger.info(
                            "Decoder graph %d node %d summary | exit=%s attrs=%d teacher_len=%d last_eos=%.3f last_max=%.3f last_idx=%d",
                            decode_stats["graph_index"],
                            node_idx,
                            attr_exit_reason,
                            t,
                            teacher_len,
                            eos_logit,
                            top_logit,
                            top_idx,
                        )

            self._enforce_required_pin_metadata(node_attributes)
            graph_payload = {
                "node_types": torch.as_tensor(node_types),
                "node_attributes": node_attributes,
                "edge_index": edges,
            }
            if hit_max_nodes_cap:
                graph_payload["_max_nodes_hit"] = True
                graph_payload["_decoder_max_nodes"] = int(self.max_nodes)
            if hit_max_edges_cap:
                graph_payload["_max_edges_hit"] = True
                graph_payload["_decoder_max_edges"] = int(self.max_edges_per_graph)
            all_graphs.append(graph_payload)
            if DEBUG_DECODER:
                attr_time = time.perf_counter() - decode_stats["attr_start"]
                total_time = decode_stats["node_time"] + attr_time
                logger.info(
                    "Decoder graph %d: nodes=%d edges=%d attr_nodes=%d attr_names=%d attr_values=%d | node_time=%.3fs attr_time=%.3fs total=%.3fs",
                    decode_stats["graph_index"],
                    decode_stats["node_count"],
                    decode_stats["edge_count"],
                    decode_stats["attr_nodes"],
                    decode_stats["attr_iters"],
                    decode_stats["attr_value_cells"],
                    decode_stats["node_time"],
                    attr_time,
                    total_time,
                )
                attr_cap_hits = 0
                teacher_cap_hits = 0
                for event in decode_stats["attr_events"]:
                    if event["exit_reason"].startswith("max_attr"):
                        attr_cap_hits += 1
                        if event["exit_reason"].endswith("teacher"):
                            teacher_cap_hits += 1
                if attr_cap_hits:
                    logger.info(
                        "Decoder graph %d attr cap hits=%d (teacher=%d, sampling=%d)",
                        decode_stats["graph_index"],
                        attr_cap_hits,
                        teacher_cap_hits,
                        attr_cap_hits - teacher_cap_hits,
                    )
            decoder_aux = {}
            if attr_teacher_tokens:
                decoder_aux["loss"] = attr_teacher_loss
                decoder_aux["attribute_tokens"] = attr_teacher_tokens
            if attr_value_teacher_tokens:
                decoder_aux["attr_value_loss"] = attr_value_teacher_loss
                decoder_aux["attr_value_tokens"] = attr_value_teacher_tokens
            if attr_dim_teacher_tokens:
                decoder_aux["attr_dim_loss"] = attr_dim_teacher_loss
                decoder_aux["attr_dim_tokens"] = attr_dim_teacher_tokens
            if node_teacher_tokens:
                decoder_aux["node_loss"] = node_teacher_loss
                decoder_aux["node_tokens"] = node_teacher_tokens
            if edge_teacher_tokens:
                decoder_aux["edge_loss"] = edge_teacher_loss
                decoder_aux["edge_tokens"] = edge_teacher_tokens
            if attr_type_mismatch_skips:
                decoder_aux["attr_type_mismatch_skips"] = attr_type_mismatch_skips
            if decoder_aux:
                return all_graphs, decoder_aux
            return all_graphs
        finally:
            _forward_prof.__exit__(None, None, None)

    def prune_latent_dims(self, kept_idx: torch.LongTensor):
        """
        Permanently remove unused latent dimensions from the node_hidden_state_init layer.
        kept_idx: 1D LongTensor of indices to keep from the original latent vector.
        """
        device = self.node_hidden_state_init.weight.device
        new_node_hidden_state_init = nn.Linear(
            kept_idx.numel(), self.node_hidden_state_init.out_features, bias=True
        ).to(device)
        new_node_hidden_state_init.weight.data.copy_(old.weight.data[:, kept_idx])

        new_node_hidden_state_init.bias.data.copy_(old.bias.data)
        self.node_hidden_state_init = new_node_hidden_state_init
        self.latent_dim = kept_idx.numel()


class InputConvexLayer(nn.Module):
    """Single ICNN layer enforcing non-negative weights on the z-term."""

    def __init__(self, input_dim: int, z_dim: int, out_dim: int, activation=F.softplus):
        super().__init__()
        self.activation = activation
        self.x_linear = nn.Linear(input_dim, out_dim)
        if z_dim > 0:
            self.z_weight = nn.Parameter(torch.empty(out_dim, z_dim))
            nn.init.xavier_uniform_(self.z_weight)
        else:
            self.z_weight = None
        self.bias = nn.Parameter(torch.zeros(out_dim))

    def forward(self, x: torch.Tensor, z_prev: Optional[torch.Tensor]):
        z_term = 0.0
        if self.z_weight is not None and z_prev is not None:
            z_term = F.linear(z_prev, F.softplus(self.z_weight), bias=None)
        return self.activation(self.x_linear(x) + z_term + self.bias)

    def prune_input(self, kept_idx: torch.LongTensor):
        kept = kept_idx.to(self.x_linear.weight.device)
        new_linear = nn.Linear(len(kept), self.x_linear.out_features).to(self.x_linear.weight.device)
        new_linear.weight.data.copy_(self.x_linear.weight.data[:, kept])
        new_linear.bias.data.copy_(self.x_linear.bias.data)
        self.x_linear = new_linear


class InputConvexNN(nn.Module):
    """Input Convex Neural Network surrogate f(z)."""

    def __init__(self, input_dim: int, hidden_dims: Sequence[int], output_dim: int, activation=F.softplus):
        super().__init__()
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.layers = nn.ModuleList()
        prev_dim = 0
        for hidden_dim in hidden_dims:
            self.layers.append(InputConvexLayer(input_dim, prev_dim, hidden_dim, activation=activation))
            prev_dim = hidden_dim
        self.final_bias = nn.Parameter(torch.zeros(output_dim))
        if prev_dim > 0:
            self.final_z_weight = nn.Parameter(torch.empty(output_dim, prev_dim))
            nn.init.xavier_uniform_(self.final_z_weight)
        else:
            self.final_z_weight = None
        self.final_linear = nn.Linear(input_dim, output_dim)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        z = None
        for layer in self.layers:
            z = layer(x, z)
        z_term = 0.0
        if z is not None and self.final_z_weight is not None:
            z_term = F.linear(z, F.softplus(self.final_z_weight), bias=None)
        return z_term + self.final_linear(x) + self.final_bias

    def prune_latent_dims(self, kept_idx: torch.LongTensor):
        for layer in self.layers:
            layer.prune_input(kept_idx)
        kept = kept_idx.to(self.final_linear.weight.device)
        new_final = nn.Linear(len(kept), self.final_linear.out_features).to(self.final_linear.weight.device)
        new_final.weight.data.copy_(self.final_linear.weight.data[:, kept])
        new_final.bias.data.copy_(self.final_linear.bias.data)
        self.final_linear = new_final


class FitnessPredictor(nn.Module):
    """
    Heteroscedastic fitness predictor implemented as a single ICNN head
    (see "Input Convex Neural Networks" by Brandon Amos, Lei Xu, J. Zico Kolter [2017]).
    """

    def __init__(
        self,
        latent_dim,
        hidden_dim=64,
        fitness_dim=4,
        icnn_hidden_dims: Optional[Sequence[int]] = None,
        icnn_activation=F.softplus,
    ):
        super().__init__()
        self.output_dim = fitness_dim
        self.latent_dim = latent_dim
        self.log_metric_scale = nn.Parameter(torch.zeros(fitness_dim))
        if icnn_hidden_dims is None:
            icnn_dims: Sequence[int] = (int(hidden_dim),) if hidden_dim else ()
        else:
            icnn_dims = tuple(int(dim) for dim in icnn_hidden_dims if int(dim) > 0)
        self.icnn = InputConvexNN(latent_dim, icnn_dims, fitness_dim, activation=icnn_activation)

    def forward(self, z_graph: torch.Tensor):
        pred = self.icnn(z_graph)
        log_scales = self.log_metric_scale.unsqueeze(0).expand(pred.size(0), -1)
        return pred, log_scales

    def prune_latent_dims(self, kept_idx: torch.LongTensor):
        self.icnn.prune_latent_dims(kept_idx)
        self.latent_dim = len(kept_idx)


class SelfCompressingFitnessRegularizedDAGVAE(nn.Module):
    """
    DAG-VAE with ARD prior that is regularized by fitness prediction from latent and has
    latent-mask for dynamic pruning.
    """

    def __init__(
        self,
        graph_encoder: GraphEncoder,
        decoder: GraphDecoder,
        fitness_predictor: FitnessPredictor,
    ):
        super().__init__()
        self.graph_encoder = graph_encoder
        self.decoder = decoder
        self.fitness_predictor = fitness_predictor
        # ARD: learnable log-precision per latent dimension
        self.log_alpha_g = nn.Parameter(torch.zeros(self.graph_encoder.latent_dim))
        # masks for active latent dims (1=active, 0=pruned)
        self.register_buffer("graph_latent_mask", torch.ones(self.graph_encoder.latent_dim))

    @property
    def shared_attr_vocab(self):
        return self.graph_encoder.shared_attr_vocab

    @property
    def attr_encoder(self):
        return self.graph_encoder.attr_encoder

    @property
    def max_value_dim(self):
        return self.graph_encoder.max_value_dim

    def encode(
        self,
        node_types,
        edge_index,
        node_attributes,
        batch,
        num_graphs=None,
    ):
        return self.graph_encoder(node_types, edge_index, node_attributes, batch, num_graphs=num_graphs)

    def reparameterize(self, mu, logvar, latent_mask):
        logvar = _sanitize_logvar(logvar)
        std = torch.exp(0.5 * logvar)
        std = _sanitize_latent_sample(std)
        mu = _sanitize_latent_sample(mu)
        z = mu + torch.randn_like(std) * std
        z = _sanitize_latent_sample(z)
        return z if latent_mask is None else z * latent_mask

    def decode(
        self,
        z,
        teacher_attr_targets: Optional[List[List[List[int]]]] = None,
        teacher_adj_targets: Optional[List[Optional[torch.Tensor]]] = None,
        teacher_attr_value_targets: Optional[List[List[List[torch.Tensor]]]] = None,
        teacher_node_types: Optional[List[Any]] = None,
    ):
        return self.decoder(
            z,
            teacher_attr_targets=teacher_attr_targets,
            teacher_adj_targets=teacher_adj_targets,
            teacher_attr_value_targets=teacher_attr_value_targets,
            teacher_node_types=teacher_node_types,
        )

    def forward(
        self,
        node_types,
        edge_index,
        node_attributes,
        batch,
        teacher_attr_targets: Optional[List[List[List[int]]]] = None,
        teacher_adj_targets: Optional[List[Optional[torch.Tensor]]] = None,
        teacher_attr_value_targets: Optional[List[List[List[torch.Tensor]]]] = None,
        teacher_node_types: Optional[List[Any]] = None,
        num_graphs: Optional[int] = None,
    ):
        mu_g, lv_g = self.encode(
            node_types,
            edge_index,
            node_attributes,
            batch,
            num_graphs=num_graphs,
        )
        graph_latent = self.reparameterize(mu_g, lv_g, self.graph_latent_mask)
        decoded = self.decode(
            graph_latent,
            teacher_attr_targets=teacher_attr_targets,
            teacher_adj_targets=teacher_adj_targets,
            teacher_attr_value_targets=teacher_attr_value_targets,
            teacher_node_types=teacher_node_types,
        )
        if isinstance(decoded, tuple):
            decoded_graphs, decoder_aux = decoded
        else:
            decoded_graphs, decoder_aux = decoded, None
        fitness_pred, metric_log_scales = self.fitness_predictor(graph_latent)
        return (
            decoded_graphs,
            fitness_pred,
            metric_log_scales,
            graph_latent,
            mu_g,
            lv_g,
            decoder_aux,
        )

    def prune_latent_dims(self, num_prune=1):
        # Identify and mask out dims with highest precision (least variance)
        def prune(latent_mask, log_alpha, desc):
            # precision = exp(log_alpha)
            latent_mask = latent_mask.cpu().numpy().astype(bool)
            precisions = torch.exp(log_alpha).detach().cpu().numpy()
            active_indices = np.where(latent_mask)[0]
            active_indices = active_indices[np.argsort(precisions[active_indices])]
            dims_to_prune = active_indices[-num_prune:]
            dims_to_prune = [d for d in dims_to_prune.tolist() if precisions[d] > 1]
            latent_mask[dims_to_prune] = 0.0
            if len(dims_to_prune) > 0:
                logger.info("Pruned %s latent dims: %s", desc, dims_to_prune)
            return torch.tensor(latent_mask)

        self.graph_latent_mask.copy_(prune(self.graph_latent_mask, self.log_alpha_g, "graph"))

    def resize_bottleneck(self):
        """
        Permanently shrink bottleneck to active dims via the per-module prune methods.
        """
        graph_kept_idx = self.graph_latent_mask.nonzero(as_tuple=True)[0]
        old_graph_dim = self.graph_latent_mask.numel()
        new_graph_dim = graph_kept_idx.numel()
        if new_graph_dim == old_graph_dim:
            logger.info("No graph latent dims to permanently prune.")
            return
        self.graph_encoder.prune_latent_dims(graph_kept_idx)
        self.decoder.prune_latent_dims(graph_kept_idx)
        self.fitness_predictor.prune_latent_dims(graph_kept_idx)
        self.log_alpha_g = nn.Parameter(self.log_alpha_g.data[graph_kept_idx].clone())
        self.register_buffer("graph_latent_mask", torch.ones(graph_kept_idx.numel()))
        logger.info("Permanently resizing graph bottleneck: %s -> %s", old_graph_dim, new_graph_dim)


@dataclass
class StagedBetaSchedule:
    """Piecewise-linear β schedule with warmup, ramp, hold, and optional cycles."""

    start_beta: float = 0.05
    target_beta: float = 0.15
    warmup_epochs: int = 0
    ramp_epochs: int = 50
    hold_epochs: int = 0
    cycle_length: Optional[int] = None
    cycle_floor: Optional[float] = None

    def __post_init__(self):
        if self.start_beta < 0 or self.target_beta < 0:
            raise ValueError("β values must be non-negative")
        for field in ("warmup_epochs", "ramp_epochs", "hold_epochs"):
            value = getattr(self, field)
            if value < 0:
                raise ValueError(f"{field} must be >= 0")
        if self.cycle_length is not None and self.cycle_length <= 0:
            raise ValueError("cycle_length must be None or > 0")

    def value(self, epoch_index: int) -> float:
        """Return β for the provided (0-indexed) global epoch count."""

        epoch = max(0, int(epoch_index))
        if epoch < self.warmup_epochs:
            return self.start_beta

        epoch -= self.warmup_epochs
        if self.ramp_epochs > 0 and epoch < self.ramp_epochs:
            ratio = min(1.0, (epoch + 1) / max(1, self.ramp_epochs))
            return self.start_beta + ratio * (self.target_beta - self.start_beta)

        epoch -= max(self.ramp_epochs, 0)
        if self.hold_epochs > 0:
            if epoch < self.hold_epochs:
                return self.target_beta
            epoch -= self.hold_epochs

        if not self.cycle_length:
            return self.target_beta

        floor = self.cycle_floor if self.cycle_floor is not None else self.start_beta
        if self.target_beta <= floor:
            return self.target_beta

        phase = epoch % self.cycle_length
        frac = phase / self.cycle_length
        return floor + frac * (self.target_beta - floor)


class OnlineTrainer:
    """
    Incremental trainer with ARD-KL + loss-thresholded iterative pruning,
    supporting variable node-feature dimensions via list-of-graphs decoding.
    """

    _BASE_MODULE_ORDER = ("encoder", "decoder", "fitness")
    _MODULE_SYNONYMS = {
        "enc": "encoder",
        "encoder": "encoder",
        "latent": "encoder",
        "dec": "decoder",
        "decoder": "decoder",
        "fitness": "fitness",
        "surrogate": "fitness",
    }

    def __init__(
        self,
        model: SelfCompressingFitnessRegularizedDAGVAE,
        optimizer,
        task=None,
        metric_keys: Optional[Sequence] = None,
        decoder_empty_penalty: float = 0.0,
        decoder_missing_node_penalty: float = 0.0,
        decoder_excess_node_penalty: float = 0.0,
        decoder_stop_loss_weight: float = 1.0,
        grad_clip_norm: float = 5.0,
        memory_tracker: MemoryUsageTracker | None = None,
    ):
        self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
        self.model = model.to(self.device)
        self.optimizer = optimizer
        self.memory_tracker = memory_tracker
        self.dataset = []
        self.invalid_dataset = []
        self._graph_signatures: Set[str] = set()
        self.loss_history = []
        self.initial_loss = None
        self._baseline_loss_buffer: list[float] = []
        self.last_prune_epoch = 0
        self.kl_scheduler: Optional[StagedBetaSchedule] = None
        self._kl_global_epoch = 0
        self.dataset_max_samples: int | None = None
        self.dataset_valid_ratio: float | None = None
        self.seed_lock_generations: int = 0
        if metric_keys is None:
            if task is None:
                raise ValueError("OnlineTrainer requires either `task` or `metric_keys`.")
            metric_keys = task.metrics
        self._update_metric_metadata(metric_keys)
        self.invalid_target_ratio = 0.2
        self.invalid_ratio_warmup = 5
        self.progress_callback = None
        self.prune_callback = None
        self.decoder_empty_penalty = float(decoder_empty_penalty or 0.0)
        self.decoder_missing_node_penalty = float(decoder_missing_node_penalty or 0.0)
        self.decoder_excess_node_penalty = float(decoder_excess_node_penalty or 0.0)
        self.decoder_stop_loss_weight = float(decoder_stop_loss_weight or 1.0)
        clip_value = float(grad_clip_norm or 0.0)
        self.grad_clip_norm = max(0.0, clip_value)
        self.wl_kernel_iterations = 2
        self.wl_loss_weight = 0.0
        self.kl_partial_slice_ratio: Optional[float] = None
        self.kl_partial_slice_dims: Optional[int] = None
        self.kl_partial_slice_start: int = 0
        self._module_param_groups = self._build_module_param_groups()
        self._module_order = tuple(name for name in self._BASE_MODULE_ORDER if name in self._module_param_groups)
        if not self._module_order:
            self._module_order = tuple(self._BASE_MODULE_ORDER[:3])  # fallback
        self.module_names_for_logging = self._module_order
        self.module_freeze_cycle: tuple[tuple[str, ...], ...] = ()
        self.module_freeze_verbose = False
        self._current_active_modules: tuple[str, ...] = self._module_order
        self._last_freeze_reason: Optional[str] = None
        self.configure_module_freeze_cycle(None)

    def _build_module_param_groups(self) -> dict[str, tuple[torch.nn.Parameter, ...]]:
        fitness = self.model.fitness_predictor
        fitness_params: list[torch.nn.Parameter] = list(fitness.parameters())
        groups: dict[str, list[torch.nn.Parameter]] = {
            "encoder": list(self.model.graph_encoder.parameters()),
            "decoder": list(self.model.decoder.parameters()),
            "fitness": fitness_params,
        }
        if hasattr(self.model, "log_alpha_g") and isinstance(self.model.log_alpha_g, torch.nn.Parameter):
            groups["encoder"].append(self.model.log_alpha_g)
        return {name: tuple(params) for name, params in groups.items() if params}

    def configure_module_freeze_cycle(self, cycle_spec: Optional[Sequence[str] | str]):
        phases = self._parse_freeze_cycle(cycle_spec)
        self.module_freeze_cycle = phases
        self._current_active_modules = phases[0]
        self._last_freeze_reason = None
        self._apply_module_freeze(self._current_active_modules, reason="freeze_init")

    def _parse_freeze_cycle(self, cycle_spec):
        if cycle_spec is None:
            specs: Sequence[str] = ()
        elif isinstance(cycle_spec, str):
            specs = [part.strip() for part in cycle_spec.split(",") if part.strip()]
        else:
            specs = list(cycle_spec)
        phases: list[tuple[str, ...]] = []
        for raw_phase in specs:
            if not raw_phase:
                continue
            tokens = [tok.strip().lower() for tok in raw_phase.split("+") if tok.strip()]
            if not tokens:
                continue
            modules: list[str] = []
            include_all = any(tok in {"all", "*"} for tok in tokens)
            if include_all:
                modules = list(self._module_order)
            else:
                for token in tokens:
                    mapped = self._MODULE_SYNONYMS.get(token)
                    if mapped and mapped in self._module_param_groups and mapped not in modules:
                        modules.append(mapped)
            if modules:
                phases.append(tuple(modules))
        if not phases:
            phases = [tuple(self._module_order)]
        return tuple(phases)

    def _modules_for_epoch(self) -> tuple[str, ...]:
        if not self.module_freeze_cycle:
            return tuple(self._module_order)
        idx = self._kl_global_epoch % len(self.module_freeze_cycle)
        return self.module_freeze_cycle[idx]

    def _apply_module_freeze(self, active_modules: Sequence[str], reason: Optional[str] = None):
        active_set = set(active_modules) if active_modules else set(self._module_order)
        changed = False
        for name, params in self._module_param_groups.items():
            enable = name in active_set
            for param in params:
                if param.requires_grad != enable:
                    param.requires_grad_(enable)
                    changed = True
        if changed:
            self.optimizer.zero_grad(set_to_none=True)
        normalized = tuple(name for name in self._module_order if name in active_set)
        self._current_active_modules = normalized or tuple(self._module_order)
        if self.module_freeze_verbose:
            label = "train " + "+".join(self._current_active_modules)
            if changed or reason != self._last_freeze_reason:
                logger.info("Trainer module freeze phase -> %s (reason=%s)", label, reason or "epoch")
        self._last_freeze_reason = reason

    def _clip_gradients(self):
        clip_value = float(getattr(self, "grad_clip_norm", 0.0) or 0.0)
        if clip_value <= 0:
            return
        params = [param for param in self.model.parameters() if param.grad is not None]
        if params:
            clip_grad_norm_(params, clip_value)

    def _update_metric_metadata(self, metric_keys: Sequence):
        self.sorted_metrics = sort_metrics_by_name(metric_keys)
        self.num_metrics = len(self.sorted_metrics)
        self.task_metric_best_values = torch.as_tensor(
            [metric.best_value for metric in self.sorted_metrics], dtype=torch.float
        )
        self.task_metric_guidance_weights = torch.as_tensor(
            [metric.guidance_weight for metric in self.sorted_metrics], dtype=torch.float
        )

    def _resolve_kl_slice_bounds(self, latent_dim: int) -> Optional[tuple[int, int]]:
        if latent_dim <= 0:
            return None
        explicit_dims = self.kl_partial_slice_dims
        if isinstance(explicit_dims, (int, float)):
            explicit_dims = int(explicit_dims)
        else:
            explicit_dims = None
        if explicit_dims is None or explicit_dims < 0:
            ratio = float(self.kl_partial_slice_ratio or 0.0)
            if ratio <= 0:
                return None
            explicit_dims = int(round(latent_dim * ratio))
            explicit_dims = max(1, min(latent_dim, explicit_dims))
        else:
            explicit_dims = max(0, min(latent_dim, explicit_dims))
        start = max(0, int(self.kl_partial_slice_start or 0))
        if start >= latent_dim:
            return None
        end = min(latent_dim, start + explicit_dims)
        if end < start:
            return None
        return start, end

    def _reduce_kl_loss(self, kl_per_dim: torch.Tensor) -> torch.Tensor:
        """Aggregate KL divergence, optionally restricting to a latent slice."""

        if kl_per_dim.dim() != 2:
            raise ValueError("kl_per_dim must be 2D [batch, latent_dim]")
        latent_dim = kl_per_dim.size(1)
        bounds = self._resolve_kl_slice_bounds(latent_dim)
        if bounds is not None:
            start, end = bounds
            kl_subset = kl_per_dim[:, start:end]
        else:
            kl_subset = kl_per_dim
        return kl_subset.sum(dim=1).mean()

    def _compute_reconstruction_losses(
        self,
        batch,
        decoded_graphs,
        decoder_aux,
        target_graph_attrs,
        *,
        teacher_node_types: Optional[Sequence[Any]] = None,
        teacher_force_weight: float = 1.0,
    ) -> tuple[torch.Tensor, torch.Tensor]:
        dense_adj = to_dense_adj(batch.edge_index, batch.batch, max_num_nodes=None)
        num_target_graphs = dense_adj.size(0)
        graphs_to_compare = min(len(decoded_graphs), num_target_graphs, len(target_graph_attrs))

        loss_adj = torch.tensor(0.0, device=self.device)
        loss_feat = torch.tensor(0.0, device=self.device)
        attribute_value_cells = 0
        empty_penalty = float(getattr(self, "decoder_empty_penalty", 0.0) or 0.0)
        missing_node_penalty = float(getattr(self, "decoder_missing_node_penalty", 0.0) or 0.0)
        excess_node_penalty = float(getattr(self, "decoder_excess_node_penalty", 0.0) or 0.0)
        empty_hits = 0

        def _resolve_node_type(seq: Any, index: int) -> Optional[int]:
            if seq is None:
                return None
            try:
                if torch.is_tensor(seq):
                    if seq.numel() == 0:
                        return None
                    flat = seq.view(-1)
                    if index >= flat.numel():
                        return None
                    return int(flat[index].item())
                if isinstance(seq, (list, tuple)):
                    if index >= len(seq):
                        return None
                    value = seq[index]
                    if torch.is_tensor(value):
                        value = value.view(-1)
                        if value.numel() == 0:
                            return None
                        return int(value[0].item())
                    return int(value)
            except Exception:
                return None
            return None

        for i in range(graphs_to_compare):
            dg = decoded_graphs[i]
            pred_edges = dg["edge_index"]
            pred_attrs = dg["node_attributes"]
            pred_node_types = dg.get("node_types")
            target_attrs = target_graph_attrs[i] if i < len(target_graph_attrs) else []
            target_type_seq = None
            if teacher_node_types is not None and i < len(teacher_node_types):
                target_type_seq = teacher_node_types[i]
            num_target_nodes = len(target_attrs)
            num_pred_nodes = len(pred_attrs)
            num_nodes = min(num_pred_nodes, num_target_nodes)
            missing_nodes = max(0, num_target_nodes - num_pred_nodes)
            if missing_node_penalty > 0 and missing_nodes > 0:
                loss_adj = loss_adj + missing_node_penalty * missing_nodes
            excess_nodes = max(0, num_pred_nodes - num_target_nodes)
            if excess_node_penalty > 0 and excess_nodes > 0:
                loss_adj = loss_adj + excess_node_penalty * excess_nodes
            if num_nodes == 0:
                empty_hits += 1
                continue
            adj_true = dense_adj[i, :num_target_nodes, :num_target_nodes]
            adj_true = adj_true[:num_nodes, :num_nodes].to(self.device)

            # build binary adjacency preds/targets on 0..num_nodes-1
            no_pred_edges = True
            adj_pred = torch.zeros((num_nodes, num_nodes), device=self.device)
            for s, d in pred_edges.t().tolist():
                if s < num_nodes and d < num_nodes:
                    adj_pred[s, d] = 1.0
                    no_pred_edges = False

            upper_mask = torch.triu(torch.ones_like(adj_pred), diagonal=1).bool()
            if adj_pred[upper_mask].size(0) > 0 and adj_true[upper_mask].size(0) > 0:
                loss_adj += F.binary_cross_entropy_with_logits(adj_pred[upper_mask], adj_true[upper_mask])
            elif adj_pred[upper_mask].size(0) > 0:
                loss_adj += adj_pred[upper_mask].sum()
            else:
                loss_adj += adj_true[upper_mask].sum()

            # node feature loss
            def convert_string(value):
                if isinstance(value, str):
                    value = self.model.attr_encoder.get_value_tensor(value)
                return value

            def to_tensor(value):
                if value is None:
                    tensor = torch.zeros(1, dtype=torch.float)
                else:
                    value = convert_string(value)
                    if isinstance(value, torch.Tensor):
                        tensor = value.detach()
                    else:
                        tensor = torch.as_tensor([value], dtype=torch.float)
                if tensor.numel() == 0:
                    tensor = torch.zeros(1, dtype=torch.float)
                return tensor.reshape(-1).float().to(self.device)

            def attribute_value_loss(value):
                tensor = to_tensor(value)
                return tensor.abs().sum(), tensor.numel()

            def mse_aligned(pred_tensor, target_tensor):
                if pred_tensor.numel() == target_tensor.numel():
                    return F.mse_loss(pred_tensor, target_tensor), pred_tensor.numel()
                size = min(pred_tensor.numel(), target_tensor.numel())
                loss = F.mse_loss(pred_tensor[:size], target_tensor[:size])
                if pred_tensor.numel() > size:
                    loss = loss + pred_tensor[size:].abs().sum()
                if target_tensor.numel() > size:
                    loss = loss + target_tensor[size:].abs().sum()
                cells = max(pred_tensor.numel(), target_tensor.numel())
                return loss, cells

            for node_idx in range(num_nodes):
                teacher_type = _resolve_node_type(target_type_seq, node_idx)
                pred_type = _resolve_node_type(pred_node_types, node_idx)
                if teacher_type is not None and pred_type is not None and teacher_type != pred_type:
                    # Attribute supervision is meaningless if the node operator mismatches.
                    continue
                all_attr_names = set(pred_attrs[node_idx].keys()) | set(target_attrs[node_idx].keys())
                for attr_name in all_attr_names:
                    pred_value = pred_attrs[node_idx].get(attr_name)
                    target_value = target_attrs[node_idx].get(attr_name)
                    if (pred_value is not None) and (target_value is not None):
                        loss_delta, cell_count = mse_aligned(to_tensor(pred_value), to_tensor(target_value))
                        loss_feat += loss_delta
                        attribute_value_cells += cell_count
                    elif target_value is not None:
                        loss_delta, cell_count = attribute_value_loss(target_value)
                        loss_feat += loss_delta
                        attribute_value_cells += cell_count
                    else:
                        loss_delta, cell_count = attribute_value_loss(pred_value)
                        loss_feat += loss_delta
                        attribute_value_cells += cell_count

        extra_attr_loss = torch.tensor(0.0, device=self.device)
        extra_adj_loss = torch.tensor(0.0, device=self.device)
        if decoder_aux is not None:
            token_count = float(decoder_aux.get("attribute_tokens", 0) or 0)
            if token_count > 0:
                ce_loss = decoder_aux["loss"] / token_count
                extra_attr_loss = extra_attr_loss + float(teacher_force_weight) * ce_loss.to(self.device)
            value_tokens = float(decoder_aux.get("attr_value_tokens", 0) or 0)
            if value_tokens > 0:
                value_loss = decoder_aux["attr_value_loss"] / value_tokens
                extra_attr_loss = extra_attr_loss + float(teacher_force_weight) * value_loss.to(self.device)
            dim_tokens = float(decoder_aux.get("attr_dim_tokens", 0) or 0)
            if dim_tokens > 0:
                dim_loss = decoder_aux["attr_dim_loss"] / dim_tokens
                extra_attr_loss = extra_attr_loss + float(teacher_force_weight) * dim_loss.to(self.device)
            node_tokens = float(decoder_aux.get("node_tokens", 0) or 0)
            if node_tokens > 0:
                node_loss = decoder_aux["node_loss"] / node_tokens
                weight = float(getattr(self, "decoder_stop_loss_weight", 1.0) or 1.0)
                extra_adj_loss = extra_adj_loss + weight * node_loss.to(self.device)
            edge_tokens = float(decoder_aux.get("edge_tokens", 0) or 0)
            if edge_tokens > 0:
                edge_loss = decoder_aux["edge_loss"] / edge_tokens
                extra_adj_loss = extra_adj_loss + edge_loss.to(self.device)

        denom = max(1, int(batch.num_graphs))
        if empty_penalty > 0 and empty_hits:
            loss_adj = loss_adj + empty_penalty * empty_hits
        loss_adj = (loss_adj + extra_adj_loss) / denom
        if attribute_value_cells > 0:
            loss_feat = loss_feat / float(attribute_value_cells)
        else:
            loss_feat = loss_feat / denom
        loss_feat = loss_feat + extra_attr_loss
        if graphs_to_compare == 0 and empty_penalty > 0:
            loss_adj = loss_adj + empty_penalty
        return _finite_loss(loss_adj), _finite_loss(loss_feat)

    def _structural_alignment_loss(self, batch, graph_latent) -> torch.Tensor:
        if self.wl_loss_weight <= 0 or graph_latent is None or batch.num_graphs <= 1:
            return torch.tensor(0.0, device=self.device)
        hist = _weisfeiler_lehman_histograms(
            batch.node_types,
            batch.edge_index,
            batch.batch,
            batch.num_graphs,
            node_attributes=getattr(batch, "node_attributes", None),
            iterations=max(1, int(getattr(self, "wl_kernel_iterations", 2) or 1)),
        )
        if hist is None or hist.numel() == 0:
            return torch.tensor(0.0, device=self.device)
        hist = hist.to(self.device)
        latent = graph_latent
        if latent.dim() != 2 or latent.size(0) != batch.num_graphs:
            return torch.tensor(0.0, device=self.device)
        wl_dist = torch.cdist(hist, hist, p=2)
        latent_dist = torch.cdist(latent, latent, p=2)
        if wl_dist.numel() == 0:
            return torch.tensor(0.0, device=self.device)
        triu_mask = torch.triu(torch.ones_like(wl_dist, dtype=torch.bool), diagonal=1)
        if triu_mask.sum() <= 0:
            return torch.tensor(0.0, device=self.device)
        wl_vals = wl_dist[triu_mask]
        latent_vals = latent_dist[triu_mask]
        wl_vals = wl_vals / wl_vals.max().clamp_min(1e-6)
        latent_vals = latent_vals / latent_vals.max().clamp_min(1e-6)
        return F.mse_loss(latent_vals, wl_vals)

    def _graph_dict_to_data(self, graph_dict: dict | None) -> Data | None:
        if not graph_dict:
            return None
        node_types = graph_dict.get("node_types")
        edge_index = graph_dict.get("edge_index")
        node_attributes = graph_dict.get("node_attributes")
        if node_types is None or edge_index is None or node_attributes is None:
            return None
        node_types = node_types.clone().detach().long()
        if isinstance(edge_index, torch.Tensor):
            edge_index = edge_index.clone().detach().long()
        else:
            edge_index = torch.as_tensor(edge_index, dtype=torch.long)
        data = Data(node_types=node_types, edge_index=edge_index, node_attributes=node_attributes)
        data.y = torch.zeros(self.num_metrics)
        return data

    def _metric_name_for_index(self, idx: int) -> str:
        if 0 <= idx < self.num_metrics:
            metric = self.sorted_metrics[idx]
            return getattr(metric, "name", str(metric))
        return f"metric_{idx}"

    def set_progress_callback(self, callback):
        """Register a callable invoked after each epoch with loss summaries."""
        self.progress_callback = callback

    def set_prune_callback(self, callback):
        """Register a callable invoked whenever latent dims are pruned."""
        self.prune_callback = callback

    def configure_kl_scheduler(self, scheduler: Optional[StagedBetaSchedule], reset_state: bool = False):
        """Attach a KL scheduler; optionally reset the accumulated epoch counter."""

        self.kl_scheduler = scheduler
        if reset_state:
            self._kl_global_epoch = 0

    def _resolve_kl_weight(self, static_weight: float) -> float:
        if self.kl_scheduler is None:
            return float(static_weight)
        return float(self.kl_scheduler.value(self._kl_global_epoch))

    def _reset_initial_loss(self, seed_value: Optional[float] = None):
        """Clear the adaptive pruning baseline and optionally seed it with the latest loss."""

        self.initial_loss = None
        self._baseline_loss_buffer.clear()
        if seed_value is not None:
            self._baseline_loss_buffer.append(float(seed_value))

    def add_data(self, graphs, fitnesses, invalid_flags=None, *, mark_seed: bool = False):
        if invalid_flags is None:
            invalid_flags = [False] * len(graphs)
        skipped = 0
        for graph, fitness_dict, is_invalid in zip(graphs, fitnesses, invalid_flags):
            signature = graph_signature_from_data(graph)
            if signature in self._graph_signatures:
                skipped += 1
                continue
            self._graph_signatures.add(signature)
            data = graph.clone()
            fitness = [float(fitness_dict[metric]) for metric in self.sorted_metrics]
            data.y = torch.as_tensor(fitness, dtype=torch.float)
            seed_flag = bool(mark_seed or getattr(graph, "_trainer_seed", False))
            data._trainer_signature = signature
            data._trainer_seed = seed_flag
            data._trainer_invalid = bool(is_invalid)
            target_list = self.invalid_dataset if is_invalid else self.dataset
            target_list.append(data)
        if skipped and DEBUG_TRAINER:
            logger.info("OnlineTrainer.add_data skipped %d duplicate graphs", skipped)

    def configure_dataset_sampling(
        self,
        *,
        max_samples: int | None = None,
        valid_ratio: float | None = None,
        seed_generations: int = 0,
    ) -> None:
        """Configure how many samples the trainer keeps per epoch."""

        if max_samples is not None:
            try:
                resolved = int(max_samples)
            except (TypeError, ValueError):
                resolved = None
            else:
                if resolved <= 0:
                    resolved = None
            max_samples = resolved
        self.dataset_max_samples = max_samples
        if valid_ratio is None:
            self.dataset_valid_ratio = None
        else:
            try:
                ratio_value = float(valid_ratio)
            except (TypeError, ValueError):
                ratio_value = None
            if ratio_value is not None:
                ratio_value = max(0.0, min(1.0, ratio_value))
            self.dataset_valid_ratio = ratio_value
        try:
            seed_generations_value = int(seed_generations)
        except (TypeError, ValueError):
            seed_generations_value = 0
        self.seed_lock_generations = max(0, seed_generations_value)

    @staticmethod
    def _partition_seed_samples(pool: List[Data]) -> tuple[list[Data], list[Data]]:
        seeds: list[Data] = []
        non_seeds: list[Data] = []
        for item in pool:
            if getattr(item, "_trainer_seed", False):
                seeds.append(item)
            else:
                non_seeds.append(item)
        return seeds, non_seeds

    @staticmethod
    def _random_subset(pool: List[Data], count: int) -> list[Data]:
        if count <= 0 or not pool:
            return []
        if count >= len(pool):
            return list(pool)
        return random.sample(pool, count)

    def _seed_lock_active(self, generation: int | None) -> bool:
        return self.seed_lock_generations > 0 and generation is not None and generation < self.seed_lock_generations

    def _build_training_samples(
        self,
        *,
        include_invalid: bool = True,
        generation: int | None = None,
    ) -> list[Data]:
        valid_pool = list(self.dataset)
        invalid_pool = list(self.invalid_dataset) if include_invalid else []
        total_available = len(valid_pool) + len(invalid_pool)
        if total_available == 0:
            return []

        seed_lock = self._seed_lock_active(generation)
        max_samples = self.dataset_max_samples
        if (not seed_lock) and (max_samples is None or max_samples <= 0 or total_available <= max_samples):
            combined = valid_pool + invalid_pool
            random.shuffle(combined)
            return combined

        if max_samples is None or max_samples <= 0:
            max_samples = total_available

        if seed_lock:
            seed_valid, remaining_valid = self._partition_seed_samples(valid_pool)
            seed_invalid, remaining_invalid = self._partition_seed_samples(invalid_pool)
        else:
            seed_valid = []
            seed_invalid = []
            remaining_valid = valid_pool
            remaining_invalid = invalid_pool

        forced_total = len(seed_valid) + len(seed_invalid)
        capacity = max(max_samples - forced_total, 0)

        if capacity == 0 and forced_total == 0:
            # No room requested but we also have no seeds, so keep earliest samples.
            combined = valid_pool + invalid_pool
            random.shuffle(combined)
            return combined

        pool_total = len(remaining_valid) + len(remaining_invalid)
        if pool_total <= 0:
            selected = seed_valid + seed_invalid
            random.shuffle(selected)
            return selected

        if self.dataset_valid_ratio is None:
            default_ratio = len(valid_pool) / max(1, len(valid_pool) + len(invalid_pool))
        else:
            default_ratio = self.dataset_valid_ratio
        default_ratio = max(0.0, min(1.0, default_ratio))

        valid_target = int(round(capacity * default_ratio))
        valid_extra = min(len(remaining_valid), valid_target)
        invalid_extra = min(len(remaining_invalid), capacity - valid_extra)
        remainder = capacity - (valid_extra + invalid_extra)
        if remainder > 0:
            valid_room = len(remaining_valid) - valid_extra
            take = min(valid_room, remainder)
            valid_extra += take
            remainder -= take
        if remainder > 0:
            invalid_room = len(remaining_invalid) - invalid_extra
            take = min(invalid_room, remainder)
            invalid_extra += take
            remainder -= take

        selected_valid = list(seed_valid)
        selected_valid.extend(self._random_subset(remaining_valid, valid_extra))
        selected_invalid = list(seed_invalid)
        selected_invalid.extend(self._random_subset(remaining_invalid, invalid_extra))

        combined = selected_valid + selected_invalid
        if not combined:
            combined = valid_pool + invalid_pool
        random.shuffle(combined)
        return combined

    def train(
        self,
        epochs=1,
        batch_size=16,
        kl_weight=10.0,
        fitness_weight=1.5,
        warmup_epochs=None,
        loss_threshold=0.9,
        min_prune_break=5,
        prune_amount=1,
        min_active_dims=5,
        stop_epsilon=1e-3,
        verbose=True,
        generation=0,
        baseline_window=5,
    ):
        if warmup_epochs is None:
            warmup_epochs = 0
        warmup_epochs = max(0, int(warmup_epochs))
        baseline_window = max(1, int(baseline_window))
        recent_loss_window = deque(maxlen=baseline_window)

        def build_epoch_loader() -> tuple[DataLoader, int] | tuple[None, int]:
            samples = self._build_training_samples(generation=generation)
            if not samples:
                return None, 0
            loader = DataLoader(samples, batch_size=batch_size, shuffle=True)
            return loader, len(samples)

        epoch_loader, dataset_size = build_epoch_loader()
        if epoch_loader is None:
            return
        total_batches = len(epoch_loader)
        train_start = time.perf_counter()
        if DEBUG_TRAINER:
            logger.info(
                "OnlineTrainer.train start | samples=%d batch_size=%d epochs=%s (resample_per_epoch=True)",
                dataset_size,
                batch_size,
                epochs,
            )
        epoch = 1
        loss_term_labels = [
            "adjacency_recon",
            "attribute_recon",
            "graph_kl",
            "fitness",
            "wl_structural",
        ]
        num_loss_terms = len(loss_term_labels)
        prev_loss_terms = torch.zeros(num_loss_terms)
        avg_loss_terms = torch.zeros(num_loss_terms)
        last_loss_term_change = float("inf")

        baseline_required = baseline_window

        def stop():
            if epochs is not None:
                return epoch > epochs
            return epoch > 1 and last_loss_term_change < stop_epsilon

        pending_loader = epoch_loader
        pending_dataset_size = dataset_size

        while not stop():
            if pending_loader is None:
                pending_loader, pending_dataset_size = build_epoch_loader()
                if pending_loader is None:
                    break
            loader = pending_loader
            dataset_size = pending_dataset_size
            pending_loader = None
            pending_dataset_size = 0
            total_batches = len(loader)
            epoch_timer = time.perf_counter() if DEBUG_TRAINER else None
            prev_loss_terms = avg_loss_terms.clone()
            total_loss_terms = torch.zeros(num_loss_terms)
            per_metric_error_sum = None
            per_metric_weight_sum = None
            self.model.train()
            active_modules = self._modules_for_epoch()
            active_label = "+".join(active_modules)
            self._apply_module_freeze(active_modules, reason=f"epoch_{self._kl_global_epoch}")
            current_kl_weight = self._resolve_kl_weight(kl_weight)
            for batch_idx, batch in enumerate(loader, start=1):
                batch_timer = time.perf_counter() if DEBUG_TRAINER else None
                batch = batch.to(self.device)
                self.optimizer.zero_grad()
                target_graph_attrs = group_node_attributes(batch.node_attributes, batch.batch)
                per_graph_node_counts = [len(attrs) for attrs in target_graph_attrs]
                teacher_node_types = group_node_types(batch.node_types, batch.batch, batch.num_graphs)
                teacher_attr_targets = build_teacher_attr_targets(
                    target_graph_attrs, None, self.model.shared_attr_vocab
                )
                teacher_attr_value_targets = build_teacher_attr_value_targets(
                    target_graph_attrs,
                    None,
                    self.model.shared_attr_vocab,
                    max_value_dim=self.model.max_value_dim,
                )
                teacher_adj_targets = build_teacher_adj_targets(batch.edge_index, batch.batch, per_graph_node_counts)
                # --- 1) forward pass ---
                if DEBUG_TRAINER:
                    logger.info(
                        "Trainer epoch %d batch %d/%d forward start | graphs=%d",
                        epoch,
                        batch_idx,
                        total_batches,
                        batch.num_graphs,
                    )
                (
                    decoded_graphs,
                    fitness_pred,
                    metric_log_scales,
                    graph_latent,
                    mu_g,
                    lv_g,
                    decoder_aux,
                ) = self.model(
                    batch.node_types,
                    batch.edge_index,
                    batch.node_attributes,
                    batch.batch,
                    teacher_attr_targets=teacher_attr_targets,
                    teacher_attr_value_targets=teacher_attr_value_targets,
                    teacher_adj_targets=teacher_adj_targets,
                    teacher_node_types=teacher_node_types,
                    num_graphs=batch.num_graphs,
                )
                target_y = batch.y

                # --- 2) reconstruction losses ---
                loss_adj, loss_feat = self._compute_reconstruction_losses(
                    batch,
                    decoded_graphs,
                    decoder_aux,
                    target_graph_attrs,
                    teacher_node_types=teacher_node_types,
                    teacher_force_weight=1.0,
                )

                # --- 3) ARD-KL losses ---
                def calc_kl_div_per_dim(log_alpha, logvar, mu):
                    # ARD-KL divergence per sample and per dim
                    log_alpha = _sanitize_log_alpha(log_alpha)
                    logvar = _sanitize_logvar(logvar)
                    mu = _sanitize_latent_sample(mu)
                    precision = torch.exp(log_alpha)
                    var = torch.exp(logvar)
                    kl = 0.5 * (-log_alpha - logvar + precision * (var + mu.pow(2)) - 1)
                    return _finite_loss(kl)

                kl_per_dim = calc_kl_div_per_dim(self.model.log_alpha_g, lv_g, mu_g)
                graph_kl_loss = _finite_loss(self._reduce_kl_loss(kl_per_dim))

                # --- 4) fitness loss ---
                target = target_y.to(self.device)
                if target.dim() == 1:
                    target = target.view(batch.num_graphs, self.num_metrics)
                best = self.task_metric_best_values.to(self.device)
                weights = self.task_metric_guidance_weights.to(self.device)
                target_canonical = canonical_log_distance(target, best)
                pred_canonical = canonical_log_distance(fitness_pred, best)
                sq_error = (pred_canonical - target_canonical).pow(2)
                hetero_term = sq_error * torch.exp(-metric_log_scales) + metric_log_scales
                weight_expand = weights.unsqueeze(0).expand_as(sq_error)
                weighted_error = hetero_term * weight_expand
                denom = weight_expand.sum().clamp_min(1.0)
                loss_fitness = weighted_error.sum() / denom
                raw_weighted_error = torch.nan_to_num(sq_error * weight_expand, nan=0.0)
                if per_metric_error_sum is None or per_metric_error_sum.numel() != weighted_error.size(-1):
                    per_metric_error_sum = torch.zeros(weighted_error.size(-1))
                    per_metric_weight_sum = torch.zeros(weighted_error.size(-1))
                per_metric_error_sum += raw_weighted_error.detach().sum(dim=0).cpu()
                per_metric_weight_sum += weight_expand.detach().sum(dim=0).cpu()

                wl_loss = self._structural_alignment_loss(batch, graph_latent)

                loss_adj = _finite_loss(loss_adj)
                loss_feat = _finite_loss(loss_feat)
                graph_kl_loss = _finite_loss(graph_kl_loss)
                loss_fitness = _finite_loss(loss_fitness)
                wl_loss = _finite_loss(wl_loss)

                # --- 5) total & backward ---
                loss_terms = [
                    loss_adj,
                    loss_feat,
                    current_kl_weight * graph_kl_loss,
                    fitness_weight * loss_fitness,
                    self.wl_loss_weight * wl_loss,
                ]
                sum(loss_terms).backward()
                self._clip_gradients()
                self.optimizer.step()
                total_loss_terms += torch.tensor(loss_terms)
                if DEBUG_TRAINER and batch_timer is not None:
                    logger.info(
                        "Trainer epoch %d batch %d/%d finished | duration=%.3fs",
                        epoch,
                        batch_idx,
                        total_batches,
                        time.perf_counter() - batch_timer,
                    )
            avg_loss_terms = total_loss_terms / len(loader)
            self.loss_history.append(avg_loss_terms.cpu().numpy())
            total_loss = float(avg_loss_terms.sum().item())
            recent_loss_window.append(total_loss)
            smoothed_loss = sum(recent_loss_window) / len(recent_loss_window)

            if self.initial_loss is None:
                if epoch < warmup_epochs:
                    self._baseline_loss_buffer.clear()
                else:
                    self._baseline_loss_buffer.append(smoothed_loss)
                    if len(self._baseline_loss_buffer) >= baseline_required:
                        self.initial_loss = sum(self._baseline_loss_buffer) / len(self._baseline_loss_buffer)
                        self._baseline_loss_buffer.clear()

            wl_idx = loss_term_labels.index("wl_structural")
            wl_value = float(avg_loss_terms[wl_idx].item())
            non_wl_total = float((avg_loss_terms.sum() - avg_loss_terms[wl_idx]).item())
            if self.wl_loss_weight > 0 and wl_value > 0 and non_wl_total > 0:
                ratio = wl_value / max(non_wl_total, 1e-8)
                if ratio > 0.5:
                    logger.warning(
                        "WL structural loss is %.2f%% of total; consider lowering wl_kernel_loss_weight to avoid overpowering reconstruction/fitness terms.",
                        ratio * 100.0,
                    )

            per_metric_losses = {}
            if per_metric_weight_sum is not None and per_metric_weight_sum.numel() > 0:
                metric_values = per_metric_error_sum / per_metric_weight_sum.clamp_min(1.0)
                metric_values = metric_values.tolist()
                weight_list = per_metric_weight_sum.tolist()
                for idx, value in enumerate(metric_values):
                    per_metric_losses[self._metric_name_for_index(idx)] = float(value)

            if self.progress_callback is not None:
                loss_metrics = {name: float(value) for name, value in zip(loss_term_labels, avg_loss_terms.tolist())}
                loss_metrics["kl_beta"] = float(current_kl_weight)
                self.progress_callback(
                    generation=generation,
                    epoch=epoch,
                    total_epochs=epochs,
                    total_loss=total_loss,
                    loss_terms=loss_metrics,
                    per_metric_losses=per_metric_losses,
                    kl_beta=float(current_kl_weight),
                    active_modules=tuple(active_modules),
                    active_modules_label=active_label,
                    available_modules=self._module_order,
                )

            if verbose:
                label_str = ", ".join(
                    f"{name}={value:.4g}" for name, value in zip(loss_term_labels, avg_loss_terms.tolist())
                )
                label_str = f"{label_str}, kl_beta={current_kl_weight:.4g}, active={active_label}"
                if not epochs:
                    logger.info(
                        "Epoch %d, Loss terms per batch: [%s] (total=%.4f)",
                        epoch,
                        label_str,
                        total_loss,
                    )
                else:
                    logger.info(
                        "Epoch %d/%d, Loss terms per batch: [%s] (total=%.4f)",
                        epoch,
                        epochs,
                        label_str,
                        total_loss,
                    )
            if DEBUG_TRAINER and epoch_timer is not None:
                logger.info(
                    "Trainer epoch %d complete | duration=%.3fs loss=%.4f",
                    epoch,
                    time.perf_counter() - epoch_timer,
                    total_loss,
                )

            # Track convergence of reconstruction terms for adaptive pruning.
            last_loss_term_change = (avg_loss_terms - prev_loss_terms).abs().max().item()
            if (
                self.initial_loss is not None
                and total_loss <= loss_threshold * self.initial_loss
                and (epoch - self.last_prune_epoch) >= min_prune_break
            ):
                active_count = int(self.model.graph_latent_mask.sum().item())
                if active_count > min_active_dims:
                    active_before = active_count
                    self.model.prune_latent_dims(num_prune=prune_amount)
                    active_after = int(self.model.graph_latent_mask.sum().item())
                    pruned_dims = active_before - active_after
                    logger.info(
                        "Latent mask pruning triggered | generation=%s epoch=%s active_before=%s "
                        "active_after=%s pruned=%s",
                        generation,
                        epoch,
                        active_before,
                        active_after,
                        pruned_dims,
                    )
                    if self.prune_callback is not None:
                        try:
                            self.prune_callback(
                                {
                                    "generation": generation,
                                    "epoch": epoch,
                                    "global_epoch": self._kl_global_epoch,
                                    "active_before": active_before,
                                    "active_after": active_after,
                                    "pruned_dims": pruned_dims,
                                }
                            )
                        except Exception:  # pragma: no cover - defensive logging
                            logger.exception("Latent prune callback failed")
                    self.last_prune_epoch = epoch
                    self._reset_initial_loss(seed_value=smoothed_loss)

            self._kl_global_epoch += 1
            epoch += 1
        if DEBUG_TRAINER:
            logger.info(
                "OnlineTrainer.train finished | epochs_run=%d duration=%.3fs",
                epoch - 1,
                time.perf_counter() - train_start,
            )
        return self.loss_history

    def teacher_force_pass(
        self,
        epochs: int,
        batch_size: int,
        teacher_force_weight: float = 2.0,
        generation: int = 0,
        verbose: bool = True,
        extra_graphs: Optional[Sequence[dict]] = None,
    ):
        epochs = max(0, int(epochs))
        if epochs == 0:
            return
        batch_size = max(1, int(batch_size))

        def build_refresh_loader() -> tuple[DataLoader, int] | tuple[None, int]:
            refresh_samples = self._build_training_samples(generation=generation)
            if extra_graphs:
                for graph_dict in extra_graphs:
                    data = self._graph_dict_to_data(graph_dict)
                    if data is not None:
                        refresh_samples.append(data)
            if not refresh_samples:
                return None, 0
            loader = DataLoader(refresh_samples, batch_size=batch_size, shuffle=True)
            return loader, len(refresh_samples)

        loader, dataset_size = build_refresh_loader()
        if loader is None:
            return
        self._apply_module_freeze(self._module_order, reason="teacher_force")
        if verbose:
            logger.info(
                "Teacher-forcing pass: epochs=%d batch_size=%d weight=%s",
                epochs,
                batch_size,
                teacher_force_weight,
            )
        for epoch in range(1, epochs + 1):
            if loader is None:
                loader, dataset_size = build_refresh_loader()
                if loader is None:
                    break
            self.model.train()
            epoch_adj = 0.0
            epoch_feat = 0.0
            batches = 0
            for batch in loader:
                batch = batch.to(self.device)
                self.optimizer.zero_grad()
                target_graph_attrs = group_node_attributes(batch.node_attributes, batch.batch)
                teacher_node_types = group_node_types(batch.node_types, batch.batch, batch.num_graphs)
                teacher_attr_targets = build_teacher_attr_targets(
                    target_graph_attrs, None, self.model.shared_attr_vocab
                )
                teacher_attr_value_targets = build_teacher_attr_value_targets(
                    target_graph_attrs,
                    None,
                    self.model.shared_attr_vocab,
                    max_value_dim=self.model.max_value_dim,
                )
                (
                    decoded_graphs,
                    _fitness_pred,
                    _metric_log_scales,
                    _graph_latent,
                    _mu_g,
                    _lv_g,
                    decoder_aux,
                ) = self.model(
                    batch.node_types,
                    batch.edge_index,
                    batch.node_attributes,
                    batch.batch,
                    teacher_attr_targets=teacher_attr_targets,
                    teacher_attr_value_targets=teacher_attr_value_targets,
                    teacher_node_types=teacher_node_types,
                    num_graphs=batch.num_graphs,
                )
                loss_adj, loss_feat = self._compute_reconstruction_losses(
                    batch,
                    decoded_graphs,
                    decoder_aux,
                    target_graph_attrs,
                    teacher_node_types=teacher_node_types,
                    teacher_force_weight=teacher_force_weight,
                )
                loss = loss_adj + loss_feat
                loss.backward()
                self._clip_gradients()
                self.optimizer.step()
                epoch_adj += float(loss_adj.detach().item())
                epoch_feat += float(loss_feat.detach().item())
                batches += 1

            avg_adj = epoch_adj / max(1, batches)
            avg_feat = epoch_feat / max(1, batches)
            if verbose:
                logger.info(
                    "Teacher force epoch %d/%d: adj_loss=%.4f attr_loss=%.4f",
                    epoch,
                    epochs,
                    avg_adj,
                    avg_feat,
                )
            if self.progress_callback is not None:
                self.progress_callback(
                    generation=generation,
                    epoch=epoch,
                    total_epochs=epochs,
                    total_loss=avg_adj + avg_feat,
                    loss_terms={"decoder_adj": avg_adj, "decoder_attr": avg_feat},
                    per_metric_losses={},
                    kl_beta=0.0,
                )
            loader = None

    def resize_bottleneck(self):
        """Rebuild all modules to permanently prune inactive dims."""
        self.model.resize_bottleneck()
        # reinit optimizer so it only holds new params
        lr = self.optimizer.defaults.get("lr", 1e-3)
        self.optimizer = torch.optim.Adam(self.model.parameters(), lr=lr)
        logger.info("Optimizer reinitialized")


if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO)
    from attributes import *

    num_node_types = 3
    max_nodes = 10
    graph_latent_dim = 32
    fitness_dim = 2
    attr_name_vocab_size = 50
    attr_name_vocab = [generate_random_string(5) for _ in range(attr_name_vocab_size)]
    shared_attr_vocab = SharedAttributeVocab(attr_name_vocab, 50)
    attr_encoder = NodeAttributeDeepSetEncoder(shared_attr_vocab, encoder_hdim=10, aggregator_hdim=20, out_dim=20)

    graph_encoder = GraphEncoder(num_node_types, attr_encoder, graph_latent_dim, hidden_dims=[32, 32])
    decoder = GraphDecoder(num_node_types, graph_latent_dim, shared_attr_vocab)
    predictor = FitnessPredictor(
        latent_dim=graph_latent_dim,
        hidden_dim=64,
        icnn_hidden_dims=(graph_latent_dim, graph_latent_dim // 2 or 1),
    )
    model = SelfCompressingFitnessRegularizedDAGVAE(graph_encoder, decoder, predictor)
    optimizer = torch.optim.Adam(model.parameters(), lr=0.001)

    # Synthetic DAG generator
    import random

    def generate_random_dag(num_nodes, num_node_types, edge_prob=0.3):
        # each node gets a random type in [0, num_node_types)
        types = torch.randint(0, num_node_types, (num_nodes,), dtype=torch.long)
        edges = []
        for i in range(num_nodes):
            for j in range(i + 1, num_nodes):
                if random.random() < edge_prob:
                    edges.append([i, j])
        edge_index = (
            torch.tensor(edges, dtype=torch.long).t().contiguous() if edges else torch.empty((2, 0), dtype=torch.long)
        )
        dyn_attrs = []
        for _ in range(num_nodes):
            attributes = {}
            for _ in range(random.randint(0, 5)):
                if random.random() <= 0.5:
                    attributes[IntAttribute(random.choice(attr_name_vocab))] = random.randint(0, 10)
                if random.random() <= 0.5:
                    attributes[FloatAttribute(random.choice(attr_name_vocab))] = random.random() * 5.0
                if random.random() <= 0.5:
                    attributes[StringAttribute(random.choice(attr_name_vocab))] = random.choice(attr_name_vocab)
            dyn_attrs.append(attributes)
        return Data(node_types=types, edge_index=edge_index, node_attributes=dyn_attrs)

    # Create synthetic dataset
    class Metric:
        def __init__(self, name, objective):
            self.name = name
            self.objective = objective

    logger.info("Generating random training data")

    def generate_data(num_samples):
        graphs, fitnesses = [], []
        task_type = random.choice(list(TASK_FEATURE_DIMS.keys()))
        task_features = torch.randn((TASK_FEATURE_DIMS[task_type],))
        for _ in range(num_samples):
            graph = generate_random_dag(random.randint(3, max_nodes), num_node_types, edge_prob=0.4)
            graphs.append(graph)
            fitnesses.append(
                {Metric(str(i), "min"): graph.edge_index.size(1) + 0.1 * random.random() for i in range(fitness_dim)}
            )
        return graphs, fitnesses, task_type, torch.randn((TASK_FEATURE_DIMS[task_type],))

    graphs, fitnesses, *_ = generate_data(50)
    metric_keys = sort_metrics_by_name(fitnesses[0].keys()) if fitnesses else []
    trainer = OnlineTrainer(model, optimizer, metric_keys=metric_keys)
    trainer.configure_kl_scheduler(
        StagedBetaSchedule(start_beta=0.0, target_beta=0.1, warmup_epochs=10, ramp_epochs=30, hold_epochs=10),
        reset_state=True,
    )
    trainer.add_data(graphs, fitnesses)
    logger.info("Training")
    trainer.train(epochs=None, batch_size=8, kl_weight=0.1, warmup_epochs=10, stop_epsilon=1)
    trainer.resize_bottleneck()

    # Continue training with new data
    graphs_new, fitnesses_new, *_ = generate_data(10)
    trainer.add_data(graphs_new, fitnesses_new)
    logger.info("Continuing training")
    trainer.train(epochs=3, batch_size=8, kl_weight=0.1)
